def begin(self, mode=None, bookmarks=None, metadata=None, timeout=None,
          db=None, imp_user=None, dehydration_hooks=None,
          hydration_hooks=None, **handlers):

    # Validar el modo
    valid_modes = ("READ", "WRITE")
    if mode is not None and mode not in valid_modes:
        raise ValueError(f"Mode must be one of {valid_modes}")

    # Construir los extras para el mensaje BEGIN
    extras = {}

    if mode is not None:
        extras["mode"] = mode

    if bookmarks:
        extras["bookmarks"] = list(bookmarks)

    if metadata:
        extras["metadata"] = metadata

    if timeout is not None:
        extras["timeout"] = timeout

    if db is not None:
        extras["db"] = db

    if imp_user is not None:
        extras["imp_user"] = imp_user

    # Configurar los hooks de serialización si se proporcionan
    if dehydration_hooks:
        self.dehydration_hooks.update(dehydration_hooks)

    if hydration_hooks:
        self.hydration_hooks.update(hydration_hooks)

    # Crear y enviar el mensaje BEGIN
    message = ("BEGIN", extras)

    # Crear objeto Response con los handlers proporcionados
    response = Response(self, message, **handlers)

    # Agregar el mensaje a la cola de salida
    self.append(message, response)

    return response

def absorb(self, args):
    """
    Dada una secuencia `args` de expresiones, devuelve una nueva lista de expresiones aplicando absorción y absorción negativa.

    Consulta https://es.wikipedia.org/wiki/Leyes_de_absorci%C3%B3n

    Absorción::

        A & (A | B) = A, A | (A & B) = A

    Absorción negativa::

        A & (~A | B) = A & B, A | (~A & B) = A | B
    """
    result = []
    for expr in args:
        if isinstance(expr, tuple) and len(expr) == 3:
            a, op, b = expr
            if op == '&':
                if (a == b) or (b == ('~', a)):
                    result.append(a)
                elif isinstance(b, tuple) and b[0] == '|':
                    if a == b[1]:
                        result.append(a)
                    elif b[1] == ('~', a):
                        result.append((a, '&', b[2]))
                    else:
                        result.append(expr)
                else:
                    result.append(expr)
            elif op == '|':
                if (a == b) or (b == ('~', a)):
                    result.append(a)
                elif isinstance(b, tuple) and b[0] == '&':
                    if a == b[1]:
                        result.append(a)
                    elif b[1] == ('~', a):
                        result.append((a, '|', b[2]))
                    else:
                        result.append(expr)
                else:
                    result.append(expr)
        else:
            result.append(expr)
    return result

import argparse

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    Dada una secuencia de argumentos y un diccionario que mapea el nombre de un subparser a una instancia de `argparse.ArgumentParser`, permite que cada subparser solicitado intente analizar todos los argumentos. Esto permite que argumentos comunes como "--repository" sean compartidos entre múltiples subparsers.

    Devuelve el resultado como una tupla que contiene: (un diccionario que mapea el nombre del subparser a un espacio de nombres (`namespace`) de argumentos analizados, una lista de argumentos restantes que no fueron reclamados por ningún subparser).
    """
    parsed_args = {}
    remaining_args = list(unparsed_arguments)

    for subparser_name, subparser in subparsers.items():
        try:
            args, remaining = subparser.parse_known_args(remaining_args)
            parsed_args[subparser_name] = args
            remaining_args = remaining
        except argparse.ArgumentError:
            continue

    return parsed_args, remaining_args

def determineMetaclass(bases, explicit_mc=None):
    """
    Determina la metaclase a partir de una o más clases base y un __metaclass__ explícito opcional.
    """
    if explicit_mc is not None:
        metaclass = explicit_mc
    elif not bases:
        metaclass = type
    else:
        metaclass = type(bases[0])
        for base in bases[1:]:
            if type(base) is not metaclass:
                raise TypeError("metaclass conflict: the metaclass of a derived class must be a (non-strict) subclass of the metaclasses of all its bases")
    return metaclass

def formatmany(
        self,
        sql: AnyStr,
        many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:

    # Convert each params set to out style
    out_params = []
    for params in many_params:
        # Format single params set
        _, converted_params = self.format(sql, params)
        out_params.append(converted_params)

    # Format SQL once using first params set
    try:
        first_params = next(iter(many_params))
    except StopIteration:
        first_params = {}

    formatted_sql, _ = self.format(sql, first_params)

    return formatted_sql, out_params

def parse_version(s: str) -> tuple[int, ...]:
    """
    comparación de versiones rudimentaria
    """
    # Split version string by dots and convert each part to integer
    return tuple(int(x) for x in s.split('.'))

def _normalizeargs(sequence, output=None):
    """
    Normalizar argumentos de declaración

    Los argumentos de normalización pueden contener Declaraciones, tuplas o interfaces individuales.

    Cualquier cosa que no sean interfaces individuales o especificaciones de implementación será expandida.
    """
    if output is None:
        output = []

    for item in sequence:
        if isinstance(item, (list, tuple)):
            _normalizeargs(item, output)
        else:
            output.append(item)

    return output

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    """
    Junto con la función :func:`generate_default_observer_schema_list`, esta función se llama de manera recursiva para generar parte de un ``observer_schema`` predeterminado a partir de una parte de un recurso de Kubernetes, definido respectivamente por ``manifest_dict`` o ``manifest_list``.

    Argumentos:
    **manifest_dict (dict):** Recursos parciales de Kubernetes.
    **first_level (bool, opcional):** Si es True, indica que el diccionario representa el esquema completo del observador (observer schema) de un recurso de Kubernetes.

    Retorna:
    **dict:** Esquema parcial generado (`observer_schema`).

    Esta función crea un nuevo diccionario a partir de ``manifest_dict`` y reemplaza todos los valores que no sean listas (`list`) ni diccionarios (`dict`) por ``None``.

    En el caso de un diccionario de ``first_level`` (es decir, un ``observer_schema`` completo para un recurso), los valores de los campos identificadores se copian del archivo de manifiesto.
    """
    observer_schema = {}

    for key, value in manifest_dict.items():
        if isinstance(value, dict):
            observer_schema[key] = generate_default_observer_schema_dict(value, first_level)
        elif isinstance(value, list):
            observer_schema[key] = [generate_default_observer_schema_dict(item, first_level) if isinstance(item, dict) else None for item in value]
        else:
            if first_level and key in ['kind', 'apiVersion', 'metadata']:
                observer_schema[key] = value
            else:
                observer_schema[key] = None

    return observer_schema

def protocol_handlers(cls, protocol_version=None):
    """
    Devuelve un diccionario de los manejadores disponibles del protocolo Bolt, indexados por una tupla de versión. Si se proporciona una versión de protocolo explícita, el diccionario contendrá cero o un elemento, dependiendo de si esa versión es soportada. Si no se proporciona ninguna versión de protocolo, se devolverán todas las versiones disponibles.

    :param protocol_version: tupla que identifica una versión específica del protocolo 
        (por ejemplo, (3, 5)) o None
    :return: diccionario que mapea una tupla de versión a la clase del manejador para 
        todas las versiones relevantes y compatibles del protocolo
    :raise TypeError: si la versión del protocolo no se pasa como una tupla
    """
    # Supongamos que tenemos un diccionario de manejadores disponibles
    available_handlers = {
        (3, 5): "HandlerForV3_5",
        (4, 0): "HandlerForV4_0",
        (4, 1): "HandlerForV4_1",
        # Agrega más versiones y manejadores según sea necesario
    }

    if protocol_version is not None:
        if not isinstance(protocol_version, tuple):
            raise TypeError("La versión del protocolo debe ser una tupla.")
        if protocol_version in available_handlers:
            return {protocol_version: available_handlers[protocol_version]}
        else:
            return {}
    else:
        return available_handlers

def render(pieces, style):
    """
    Renderiza las piezas de versión dadas en el estilo solicitado.

    :param pieces: Diccionario con las piezas de la versión.
    :param style: Estilo de renderizado (por ejemplo, 'full', 'short', etc.).
    :return: Versión renderizada como cadena de texto.
    """
    if style == 'full':
        return f"{pieces['major']}.{pieces['minor']}.{pieces['patch']}"
    elif style == 'short':
        return f"{pieces['major']}.{pieces['minor']}"
    elif style == 'patch':
        return f"{pieces['patch']}"
    else:
        raise ValueError(f"Estilo '{style}' no soportado.")

def status_str(self, prefix=''):
    """
    Devuelve una cadena con el estado del validador, con un prefijo opcional.
    """
    # Asumiendo que el validador tiene atributos que representan su estado
    status = f"{prefix}Estado del validador: "
    if hasattr(self, 'is_valid'):
        status += "Válido" if self.is_valid else "Inválido"
    if hasattr(self, 'last_checked'):
        status += f", Última verificación: {self.last_checked}"
    if hasattr(self, 'error_message'):
        status += f", Mensaje de error: {self.error_message}"
    return status

def formatmany(
                self,
                sql: AnyStr,
                many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
        ) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:
    # Determine the parameter style based on the SQL query
    if self.SQLParams.in_style == 'named':
        # Convert to named parameters
        formatted_sql = sql
        out_params = []
        for params in many_params:
            out_param = {}
            for key, value in params.items():
                out_param[key] = value
                formatted_sql = formatted_sql.replace(f":{key}", "%s")
            out_params.append(out_param)
    else:
        # Convert to ordinal parameters
        formatted_sql = sql
        out_params = []
        for params in many_params:
            out_param = list(params)
            out_params.append(out_param)
            for index in range(len(params)):
                formatted_sql = formatted_sql.replace(f"${index + 1}", "%s")

    return formatted_sql, out_params

import re

class ValidationError(Exception):
    def __init__(self, messages):
        self.messages = messages

def _validate_labels(labels):
    errors = []
    key_regex = r'^[a-zA-Z0-9_]+$'  # Example regex for keys
    value_regex = r'^[a-zA-Z0-9_]+$'  # Example regex for values

    for key, value in labels.items():
        if not isinstance(key, str) or not re.match(key_regex, key):
            errors.append({key: f"La clave de la etiqueta '{key}' no coincide con la expresión regular [...]"})

        if not isinstance(value, str) or not re.match(value_regex, value):
            errors.append({str(value): 'se esperaba un objeto de tipo cadena o bytes'})

    if errors:
        raise ValidationError(errors)

