public class CharUtils {
    /**
     * <p>Verifica si el carácter es ASCII de 7 bits.</p>
     * <pre>
     * CharUtils.isAscii('a')  = true
     * CharUtils.isAscii('A')  = true 
     * CharUtils.isAscii('3')  = true
     * CharUtils.isAscii('-')  = true
     * CharUtils.isAscii('\n') = true
     * CharUtils.isAscii('&copy;') = false
     * </pre>
     * @param ch el carácter a verificar
     * @return true si es menor que 128
     */
    public static boolean isAscii(final char ch) {
        return ch < 128;
    }
}

import java.util.*;

public class Graph<V,E> {

    // Graph representation using adjacency lists
    private Map<V, List<Edge<V,E>>> adjacencyMap;

    private class Edge<V,E> {
        private V source;
        private V target; 
        private E data;

        public Edge(V source, V target, E data) {
            this.source = source;
            this.target = target;
            this.data = data;
        }
    }

    /** 
     * Calcula todos los vértices que tienen un grado positivo iterando sobre las aristas intencionadamente. 
     * Esto mantiene la complejidad en O(m) donde m es el número de aristas.
     * @return conjunto de vértices con grado positivo
     */
    private Set<V> initVisibleVertices() {
        Set<V> visibleVertices = new HashSet<>();

        // Iterate through all vertices and their edges
        for (Map.Entry<V, List<Edge<V,E>>> entry : adjacencyMap.entrySet()) {
            V vertex = entry.getKey();
            List<Edge<V,E>> edges = entry.getValue();

            // If vertex has any edges, add it to visible set
            if (!edges.isEmpty()) {
                visibleVertices.add(vertex);

                // Also add all target vertices of the edges
                for (Edge<V,E> edge : edges) {
                    visibleVertices.add(edge.target);
                }
            }
        }

        return visibleVertices;
    }
}

import java.io.IOException;
import java.io.InputStream;

public class BufferedReader {
    private byte[] buffer;
    private int pos;
    private int count;
    private InputStream in;
    private static final int BUFFER_SIZE = 8192;

    public BufferedReader(InputStream in) {
        this.in = in;
        this.buffer = new byte[BUFFER_SIZE];
        this.pos = 0;
        this.count = 0;
    }

    /**
     * Lee un byte del <code>buffer</code> y lo vuelve a llenar según sea necesario.
     * @return El siguiente byte del flujo de entrada.
     * @throws IOException si no hay más datos disponibles.
     */
    public byte readByte() throws IOException {
        // Si el buffer está vacío o hemos llegado al final, rellenarlo
        if (pos >= count) {
            count = in.read(buffer);
            pos = 0;

            // Si no hay más datos para leer
            if (count == -1) {
                throw new IOException("No hay más datos disponibles");
            }
        }

        // Devolver el siguiente byte y actualizar la posición
        return buffer[pos++];
    }
}

import java.util.HashSet;
import java.util.Set;

public class Graph<V> {
    private Set<V> vertices;
    private Set<Edge<V>> edges;

    public Graph() {
        this.vertices = new HashSet<>();
        this.edges = new HashSet<>();
    }

    public void addVertex(V vertex) {
        vertices.add(vertex);
    }

    public void addEdge(V source, V destination) {
        edges.add(new Edge<>(source, destination));
        addVertex(source);
        addVertex(destination);
    }

    /** 
     * Calcula todos los vértices que tienen un grado positivo iterando sobre las aristas intencionadamente. 
     * Esto mantiene la complejidad en $O(m)$ donde $m$ es el número de aristas.
     * @return conjunto de vértices con grado positivo
     */
    private Set<V> initVisibleVertices() {
        Set<V> visibleVertices = new HashSet<>();
        for (Edge<V> edge : edges) {
            visibleVertices.add(edge.source);
            visibleVertices.add(edge.destination);
        }
        return visibleVertices;
    }

    private static class Edge<V> {
        V source;
        V destination;

        Edge(V source, V destination) {
            this.source = source;
            this.destination = destination;
        }
    }
}

public class CharUtils {

    private static final String[] CHAR_STRING_CACHE = new String[128];

    static {
        for (char c = 0; c < CHAR_STRING_CACHE.length; c++) {
            CHAR_STRING_CACHE[c] = String.valueOf(c);
        }
    }

    /**
     * <p>Convierte el carácter en una cadena que contiene un solo carácter.</p>
     * <p>Para caracteres ASCII de 7 bits, utiliza una caché que devolverá el mismo objeto String cada vez.</p>
     * <pre>
     * CharUtils.toString(' ')  = " "
     * CharUtils.toString('A')  = "A"
     * </pre>
     * @param ch  el carácter a convertir
     * @return una cadena que contiene el carácter especificado
     */
    public static String toString(final char ch) {
        if (ch < CHAR_STRING_CACHE.length) {
            return CHAR_STRING_CACHE[ch];
        }
        return String.valueOf(ch);
    }

    public static void main(String[] args) {
        System.out.println(toString(' '));  // Output: " "
        System.out.println(toString('A'));  // Output: "A"
        System.out.println(toString('€'));  // Output: "€" (non-ASCII character)
    }
}

import java.nio.charset.Charset;
import java.nio.charset.IllegalCharsetNameException;
import java.nio.charset.UnsupportedCharsetException;

public class CharsetTranslator {

    /**
     * Traduce un nombre de conjunto de caracteres estándar MIME al equivalente en Java.
     * @param charset El nombre estándar MIME.
     * @return El equivalente en Java para este nombre.
     */
    private static String javaCharset(String charset) {
        try {
            // Intenta obtener el Charset correspondiente al nombre MIME
            Charset javaCharset = Charset.forName(charset);
            return javaCharset.name();
        } catch (IllegalCharsetNameException | UnsupportedCharsetException e) {
            // Si el nombre no es válido o no es soportado, devuelve el charset por defecto (UTF-8)
            return Charset.defaultCharset().name();
        }
    }

    public static void main(String[] args) {
        // Ejemplo de uso
        String mimeCharset = "ISO-8859-1";
        String javaCharset = javaCharset(mimeCharset);
        System.out.println("El equivalente en Java para " + mimeCharset + " es: " + javaCharset);
    }
}

import java.io.IOException;
import java.io.OutputStream;

public class ByteArrayOutputStream extends OutputStream {

    protected byte[] buf;
    protected int count;

    @Override
    public void write(byte b[]) throws IOException {
        if (b == null) {
            throw new NullPointerException();
        }

        // Ensure capacity
        int newcount = count + b.length;
        if (newcount > buf.length) {
            byte newbuf[] = new byte[Math.max(buf.length << 1, newcount)];
            System.arraycopy(buf, 0, newbuf, 0, count);
            buf = newbuf;
        }

        // Copy bytes to buffer
        System.arraycopy(b, 0, buf, count, b.length);
        count = newcount;
    }
}

import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.util.regex.MatchResult;

public final class URIMatcher {

    private final Pattern pattern;

    public URIMatcher(String regex) {
        this.pattern = Pattern.compile(regex);
    }

    /**
     * Compara una URI con el patrón.
     * @param uri la URI a comparar con la plantilla.
     * @return el resultado de la coincidencia, o null si no hay coincidencia.
     */
    public final MatchResult match(CharSequence uri) {
        Matcher matcher = pattern.matcher(uri);
        if (matcher.matches()) {
            return matcher.toMatchResult();
        } else {
            return null;
        }
    }

    public static void main(String[] args) {
        URIMatcher matcher = new URIMatcher("https://example.com/.*");
        MatchResult result = matcher.match("https://example.com/resource");
        if (result != null) {
            System.out.println("Match found: " + result.group());
        } else {
            System.out.println("No match found.");
        }
    }
}

import org.jgrapht.Graph;
import org.jgrapht.GraphPath;
import org.jgrapht.graph.GraphWalk;
import java.util.*;

public class GraphUtils {

    protected <V,E> GraphPath<V,E> edgeSetToTour(Set<E> tour, Graph<V,E> graph) {
        if (tour == null || tour.isEmpty() || graph == null) {
            return null;
        }

        // Create lists to store vertices and edges of the path
        List<V> vertexList = new ArrayList<>();
        List<E> edgeList = new ArrayList<>();

        // Get first edge and its vertices
        E firstEdge = tour.iterator().next();
        V startVertex = graph.getEdgeSource(firstEdge);
        V currentVertex = graph.getEdgeTarget(firstEdge);

        // Add first vertex and edge
        vertexList.add(startVertex);
        edgeList.add(firstEdge);

        // Remove first edge from set
        Set<E> remainingEdges = new HashSet<>(tour);
        remainingEdges.remove(firstEdge);

        // Build path by connecting edges
        while (!remainingEdges.isEmpty()) {
            vertexList.add(currentVertex);

            // Find next edge that connects to current vertex
            E nextEdge = null;
            for (E edge : remainingEdges) {
                if (graph.getEdgeSource(edge).equals(currentVertex)) {
                    nextEdge = edge;
                    currentVertex = graph.getEdgeTarget(edge);
                    break;
                } else if (graph.getEdgeTarget(edge).equals(currentVertex)) {
                    nextEdge = edge;
                    currentVertex = graph.getEdgeSource(edge);
                    break;
                }
            }

            if (nextEdge == null) {
                throw new IllegalArgumentException("Invalid tour: edges do not form a continuous path");
            }

            edgeList.add(nextEdge);
            remainingEdges.remove(nextEdge);
        }

        // Add final vertex to complete the path
        vertexList.add(currentVertex);

        // Calculate total weight of path
        double weight = 0.0;
        for (E edge : edgeList) {
            weight += graph.getEdgeWeight(edge);
        }

        return new GraphWalk<>(graph, vertexList, edgeList, weight);
    }
}

public class CharUtils {
