    }
}

import java.util.Objects;

public class Bucket {
    private Bucket prev;
    private Bucket next;

    /**
     * Inserta este "bucket" en la estructura de datos antes del {@code bucket}.
     * @param bucket el "bucket", que será el siguiente a este "bucket".
     */
    public void insertBefore(Bucket bucket) {
        Objects.requireNonNull(bucket, "bucket cannot be null");

        // Set this bucket's next reference to the given bucket
        this.next = bucket;

        // Set this bucket's prev reference to the given bucket's previous
        this.prev = bucket.prev;

        // Update the given bucket's prev reference to point to this bucket
        bucket.prev = this;

        // If there was a previous bucket, update its next reference
        if (this.prev != null) {
            this.prev.next = this;
        }
    }
}

import org.objectweb.asm.Label;

/**
 * Devuelve la etiqueta correspondiente al "offset" del bytecode dado. La implementación predeterminada de este método crea una etiqueta para el desplazamiento dado si aún no se ha creado.
 * @param bytecodeOffset un "offset" de bytecode en un método.
 * @param labels las etiquetas ya creadas, indexadas por su "offset". Si ya existe una etiqueta para bytecodeOffset, este método no debe crear una nueva. De lo contrario, debe almacenar la nueva etiqueta en este arreglo.
 * @return una etiqueta no nula, que debe ser igual a labels[bytecodeOffset].
 */
protected Label readLabel(final int bytecodeOffset, final Label[] labels) {
    if (labels[bytecodeOffset] == null) {
        labels[bytecodeOffset] = new Label();
    }
    return labels[bytecodeOffset];
}

import java.util.Stack;

public class FrameStackHandler {
    private Stack<Object> frameStack;

    public FrameStackHandler() {
        this.frameStack = new Stack<>();
    }

    /**
     * Extrae tantos tipos abstractos de la "frame stack" de salida como lo describe el descriptor dado.
     * @param descriptor un descriptor de tipo o método (en cuyo caso se extraen sus tipos de argumento).
     */
    private void pop(final String descriptor) {
        int index = 0;
        while (index < descriptor.length()) {
            char c = descriptor.charAt(index);
            switch (c) {
                case '(':
                    // Skip opening parenthesis for method descriptors
                    index++;
                    continue;
                case ')':
                    // End of method parameters
                    return;
                case 'B':
                case 'C':
                case 'I':
                case 'S':
                case 'Z':
                case 'F':
                    // Pop single-slot types
                    frameStack.pop();
                    index++;
                    break;
                case 'J':
                case 'D':
                    // Pop double-slot types
                    frameStack.pop();
                    frameStack.pop();
                    index++;
                    break;
                case 'L':
                    // Skip reference type name until semicolon
                    frameStack.pop();
                    index = descriptor.indexOf(';', index) + 1;
                    break;
                case '[':
                    // Skip array dimensions
                    while (descriptor.charAt(index) == '[') {
                        index++;
                    }
                    if (descriptor.charAt(index) == 'L') {
                        index = descriptor.indexOf(';', index) + 1;
                    } else {
                        index++;
                    }
                    frameStack.pop();
                    break;
                default:
                    throw new IllegalArgumentException("Invalid descriptor: " + descriptor);
            }
        }
    }
}

import java.util.Iterator;
import java.util.List;

public class GraphIterator implements Iterator<Vertex> {
    private List<Vertex> vertices;
    private boolean[] visited;
    private int currentIndex;

    public GraphIterator(List<Vertex> vertices) {
        this.vertices = vertices;
        this.visited = new boolean[vertices.size()];
        this.currentIndex = 0;
    }

    @Override
    public boolean hasNext() {
        while (currentIndex < vertices.size()) {
            if (!visited[currentIndex]) {
                return true;
            }
            currentIndex++;
        }
        return false;
    }

    @Override
    public Vertex next() {
        if (!hasNext()) {
            throw new NoSuchElementException();
        }
        Vertex vertex = vertices.get(currentIndex);
        visited[currentIndex] = true;
        currentIndex++;
        return vertex;
    }
}

