def _convert_non_cli_args(self, parser_name, values_dict):
    """
    Converte gli argomenti nei tipi corretti modificando il parametro values_dict.

    Per impostazione predefinita, tutti i valori sono stringhe.

    :param parser_name: Il nome del comando, ad esempio main, virsh, ospd, ecc.
    :param values_dict: Il dizionario con gli argomenti
    """
    for key, value in values_dict.items():
        if isinstance(value, str):
            if value.lower() == 'true':
                values_dict[key] = True
            elif value.lower() == 'false':
                values_dict[key] = False
            elif value.isdigit():
                values_dict[key] = int(value)
            elif value.replace('.', '', 1).isdigit():
                values_dict[key] = float(value)
            elif value.lower() == 'none':
                values_dict[key] = None
    return values_dict

def hist_to_graph(hist, make_value=None, get_coordinate="left",
                  field_names=("x", "y"), scale=None):

    # Default make_value function just returns bin content
    if make_value is None:
        make_value = lambda x: x

    # Get coordinate mapping functions
    coordinate_funcs = {
        "left": lambda bin_: bin_.edges[0],
        "right": lambda bin_: bin_.edges[1], 
        "middle": lambda bin_: (bin_.edges[0] + bin_.edges[1])/2
    }

    get_coord = coordinate_funcs[get_coordinate]

    # Create points list
    points = []
    for bin_ in hist:
        x = get_coord(bin_)
        y = make_value(bin_.value)

        # Handle single values vs tuples
        if isinstance(y, tuple):
            points.append((x,) + y)
        else:
            points.append((x, y))

    # Set scale if requested
    if scale is True:
        scale = hist.scale

    # Create field names based on number of values
    if len(points[0]) != len(field_names):
        raise ValueError("Number of field names must match number of values per point")

    # Import Graph class and create new graph
    from .graph import Graph
    return Graph(points, field_names=field_names, scale=scale)

def dict_insert(dic, val, key, *keys):
    if not keys:
        # Base case - no more nested keys, insert value directly
        dic[key] = val
        return

    # Create nested dictionary if it doesn't exist
    if key not in dic:
        dic[key] = {}
    elif not isinstance(dic[key], dict):
        # Convert existing value to dict if needed
        dic[key] = {}

    # Recursively insert into nested dictionary
    dict_insert(dic[key], val, keys[0], *keys[1:])

def run_command(comandi, argomenti, cwd=None, verbose=False, nascondi_stderr=False, env=None):
    """
    Esegui il comando specificato.
    """
    import subprocess
    import sys

    # Costruisci il comando completo
    if isinstance(comandi, str):
        cmd = [comandi]
    else:
        cmd = list(comandi)

    if argomenti:
        if isinstance(argomenti, str):
            cmd.append(argomenti)
        else:
            cmd.extend(argomenti)

    # Imposta gli stream di output
    stdout = subprocess.PIPE
    stderr = subprocess.DEVNULL if nascondi_stderr else subprocess.PIPE

    try:
        # Esegui il comando
        process = subprocess.Popen(
            cmd,
            stdout=stdout,
            stderr=stderr,
            cwd=cwd,
            env=env,
            universal_newlines=True
        )

        # Leggi l'output
        out, err = process.communicate()

        # Stampa l'output se verbose è True
        if verbose:
            if out:
                print(out)
            if err and not nascondi_stderr:
                print(err, file=sys.stderr)

        return process.returncode, out, err

    except Exception as e:
        if verbose:
            print(f"Errore nell'esecuzione del comando: {e}", file=sys.stderr)
        return -1, "", str(e)

