/**
 * Funzione di supporto per decodificare metà di un numero esadecimale da una stringa.
 * @param c Il carattere ASCII del numero esadecimale da decodificare. Deve essere compreso nell'intervallo {@code [0-9a-fA-F}.
 * @return Il valore esadecimale rappresentato dal carattere ASCII fornito, oppure {@link Character#MAX_VALUE} se il carattere non è valido.
 */
private static char decodeHexNibble(final char c) {
    if (c >= '0' && c <= '9') {
        return (char) (c - '0');
    } else if (c >= 'a' && c <= 'f') {
        return (char) (c - 'a' + 10);
    } else if (c >= 'A' && c <= 'F') {
        return (char) (c - 'A' + 10);
    } else {
        return Character.MAX_VALUE;
    }
}

public class DiagnosticContext {
    private static final ThreadLocal<Stack<String>> contextStack = ThreadLocal.withInitial(Stack::new);

    /** 
     * Osserva l'ultimo contesto diagnostico in cima a questo NDC senza rimuoverlo. <p>Il valore restituito è il valore che è stato inserito per ultimo. Se non è disponibile alcun contesto, viene restituita la stringa vuota "".
     * @return String Il contesto diagnostico più interno.
     */
    public static String peek() {
        Stack<String> stack = contextStack.get();
        return stack.isEmpty() ? "" : stack.peek();
    }

    public static void push(String context) {
        contextStack.get().push(context);
    }

    public static void pop() {
        Stack<String> stack = contextStack.get();
        if (!stack.isEmpty()) {
            stack.pop();
        }
    }

    public static void main(String[] args) {
        push("Context1");
        push("Context2");
        System.out.println(peek()); // Should print "Context2"
        pop();
        System.out.println(peek()); // Should print "Context1"
        pop();
        System.out.println(peek()); // Should print ""
    }
}

public class ArrayUtils {
    /**
     * <p>Clona un array restituendo un risultato di tipo cast e gestendo <code>null</code>.</p>
     * <p>Questo metodo restituisce <code>null</code> per un array di input <code>null</code>.</p>
     * 
     * @param array l'array da clonare, può essere <code>null</code>
     * @return l'array clonato, <code>null</code> se l'input è <code>null</code>
     */
    public static char[] clone(final char[] array) {
        if (array == null) {
            return null;
        }

        char[] result = new char[array.length];
        System.arraycopy(array, 0, result, 0, array.length);
        return result;
    }
}

