import java.util.Objects;

public class DoublyLinkedList<E> {

    private static class ListNodeImpl<E> {
        E element;
        ListNodeImpl<E> prev;
        ListNodeImpl<E> next;

        ListNodeImpl(E element, ListNodeImpl<E> prev, ListNodeImpl<E> next) {
            this.element = element;
            this.prev = prev;
            this.next = next;
        }
    }

    private ListNodeImpl<E> head;
    private ListNodeImpl<E> tail;
    private int size;

    public DoublyLinkedList() {
        head = null;
        tail = null;
        size = 0;
    }

    private void addListNode(ListNodeImpl<E> node) {
        if (head == null) {
            head = node;
            tail = node;
        } else {
            tail.next = node;
            node.prev = tail;
            tail = node;
        }
        size++;
    }

    private void removeListNode(ListNodeImpl<E> node) {
        if (node.prev != null) {
            node.prev.next = node.next;
        } else {
            head = node.next;
        }

        if (node.next != null) {
            node.next.prev = node.prev;
        } else {
            tail = node.prev;
        }

        node.prev = null;
        node.next = null;
        size--;
    }

    private void moveAllListNodes(DoublyLinkedList<E> list) {
        Objects.requireNonNull(list, "The input list cannot be null");

        if (list.head == null) {
            return; // Nothing to move
        }

        // Remove all nodes from the input list
        ListNodeImpl<E> current = list.head;
        while (current != null) {
            ListNodeImpl<E> next = current.next;
            list.removeListNode(current);
            this.addListNode(current);
            current = next;
        }
    }
}

import org.apache.log4j.spi.LoggingEvent;
import java.util.ArrayList;
import java.util.List;

public class LogBuffer {
    private List<LoggingEvent> buffer;
    private static final int MAX_BUFFER_SIZE = 1000;

    public LogBuffer() {
        buffer = new ArrayList<>();
    }

    /**
     * Aggiunge un <code>evento</code> come ultimo evento nel buffer.
     */
    public void add(LoggingEvent event) {
        if (event == null) {
            return;
        }

        // Remove oldest event if buffer is full
        if (buffer.size() >= MAX_BUFFER_SIZE) {
            buffer.remove(0);
        }

        // Add new event to end of buffer
        buffer.add(event);
    }
}

import java.util.HashMap;
import java.util.Map;

public class SymbolTable {
    private final Map<String, Integer> constantPool;
    private int nextIndex;

    public SymbolTable() {
        this.constantPool = new HashMap<>();
        this.nextIndex = 0;
    }

    /**
     * Aggiunge un CONSTANT_NameAndType_info al pool di costanti di questa tabella dei simboli. Non fa nulla se il pool di costanti contiene già un elemento simile.
     * @param name il nome di un campo o di un metodo.
     * @param descriptor un descrittore di campo o di metodo.
     * @return un nuovo simbolo o un simbolo già esistente con il valore fornito.
     */
    public int addConstantNameAndType(final String name, final String descriptor) {
        String key = name + ":" + descriptor;
        if (!constantPool.containsKey(key)) {
            constantPool.put(key, nextIndex);
            nextIndex++;
        }
        return constantPool.get(key);
    }

    public static void main(String[] args) {
        SymbolTable symbolTable = new SymbolTable();
        int index1 = symbolTable.addConstantNameAndType("myMethod", "(I)V");
        int index2 = symbolTable.addConstantNameAndType("myMethod", "(I)V");
        System.out.println("Index of first addition: " + index1);
        System.out.println("Index of second addition (should be the same): " + index2);
    }
}

import java.io.File;

public class FileUtils {

    /**
     * Rimuove l'estensione del nome file dal percorso fornito, ad esempio "mypath/myfile.txt" -> "mypath/myfile".
     * @param path il percorso del file (può essere <code>null</code>)
     * @return il percorso con l'estensione del nome file rimossa, oppure <code>null</code> se non presente
     */
    public static String stripFilenameExtension(String path) {
        if (path == null) {
            return null;
        }

        int lastDotIndex = path.lastIndexOf('.');
        if (lastDotIndex == -1) {
            // No extension found
            return path;
        }

        int lastSeparatorIndex = path.lastIndexOf(File.separator);
        if (lastSeparatorIndex > lastDotIndex) {
            // Last dot is in the path portion, not the filename
            return path;
        }

        return path.substring(0, lastDotIndex);
    }
}

/**
 * <p>Controlla se una Stringa inizia con un prefisso specificato (opzionalmente senza distinzione tra maiuscole e minuscole).</p>
 * @see String#startsWith(String)
 * @param str  la Stringa da controllare, può essere null
 * @param prefix il prefisso da trovare, può essere null
 * @param ignoreCase indica se il confronto deve ignorare le maiuscole e minuscole (senza distinzione tra maiuscole e minuscole) o meno.
 * @return <code>true</code> se la Stringa inizia con il prefisso o entrambi <code>null</code>
 */
private static boolean startsWith(final String str, final String prefix, final boolean ignoreCase) {
    if (str == null && prefix == null) {
        return true;
    }
    if (str == null || prefix == null) {
        return false;
    }
    if (ignoreCase) {
        return str.toLowerCase().startsWith(prefix.toLowerCase());
    } else {
        return str.startsWith(prefix);
    }
}

