import java.util.List;
import java.util.ArrayList;
import java.util.Collections;

public class UpperBoundCalculator<K extends Comparable<K>> {

    /**
     * Trova un limite superiore minimo per ogni chiave.
     * @param keys una lista di chiavi.
     * @return il limite superiore delle chiavi calcolato.
     */
    private List<Integer> computeUpperBounds(List<K> keys) {
        if (keys == null || keys.isEmpty()) {
            return new ArrayList<>();
        }

        // Ordina la lista di chiavi
        List<K> sortedKeys = new ArrayList<>(keys);
        Collections.sort(sortedKeys);

        List<Integer> upperBounds = new ArrayList<>();
        for (K key : keys) {
            // Trova l'indice del primo elemento maggiore di key
            int index = Collections.binarySearch(sortedKeys, key);
            if (index < 0) {
                index = -index - 1;
            } else {
                index = index + 1;
            }

            // Se l'indice è fuori dai limiti, non c'è un limite superiore
            if (index >= sortedKeys.size()) {
                upperBounds.add(null);
            } else {
                upperBounds.add(index);
            }
        }

        return upperBounds;
    }
}

public class ParameterSeparatorChecker {

    /** 
     * Determina se un nome di parametro termina nella posizione attuale, cioè se il carattere fornito può essere considerato un separatore. 
     */
    private static boolean isParameterSeparator(final char c) {
        // Consider common parameter separators
        return c == ',' || c == ';' || c == '&' || c == '|' || c == ' ' || c == '\n' || c == '\t';
    }

    public static void main(String[] args) {
        // Test the isParameterSeparator method
        char testChar1 = ',';
        char testChar2 = 'a';

        System.out.println(isParameterSeparator(testChar1)); // true
        System.out.println(isParameterSeparator(testChar2)); // false
    }
}

public class ArrayCloner {

    /** 
     * <p>Clona un array restituendo un risultato di tipo cast e gestendo <code>null</code>.</p> 
     * <p>Questo metodo restituisce <code>null</code> per un array di input <code>null</code>.</p>
     * @param array  l'array da clonare, può essere <code>null</code>
     * @return l'array clonato, <code>null</code> se l'input è <code>null</code>
     */
    public static char[] clone(final char[] array) {
        if (array == null) {
            return null;
        }
        char[] clonedArray = new char[array.length];
        System.arraycopy(array, 0, clonedArray, 0, array.length);
        return clonedArray;
    }

    public static void main(String[] args) {
        char[] original = {'a', 'b', 'c'};
        char[] cloned = clone(original);

        // Print the cloned array
        if (cloned != null) {
            for (char c : cloned) {
                System.out.print(c + " ");
            }
        } else {
            System.out.println("Cloned array is null.");
        }
    }
}

