public class CollectionUtils {
    /**
     * Converte la Collection fornita in un array di Stringhe. L'array restituito non contiene elementi <code>null</code>. 
     * Si noti che {@link Arrays#sort(Object[])} genererà un {@link NullPointerException} se un elemento dell'array è <code>null</code>.
     * @param collection La collezione da convertire
     * @return Un nuovo array di Stringhe.
     */
    static String[] toNoNullStringArray(Collection<?> collection) {
        if (collection == null) {
            return new String[0];
        }

        return collection.stream()
                .filter(Objects::nonNull)
                .map(Object::toString)
                .toArray(String[]::new);
    }
}

import java.util.*;

public class GraphTraversal implements Iterator<Vertex> {
    private boolean[] visited;
    private int numVertices;

    @Override
    public boolean hasNext() {
        // Iterate through visited array to check if any vertices are unvisited
        for (int i = 0; i < numVertices; i++) {
            if (!visited[i]) {
                return true;
            }
        }
        return false;
    }
}

import java.awt.geom.Point2D;

public class PointComparator {
    /** 
     * Confronta due punti per uguaglianza utilizzando una tolleranza di 1e-9.
     * @param p1 il primo punto
     * @param p2 il secondo punto
     * @return se i due punti sono uguali o meno
     */
    public static boolean equals(Point2D p1, Point2D p2) {
        if (p1 == null || p2 == null) {
            return false;
        }
        double tolerance = 1e-9;
        return Math.abs(p1.getX() - p2.getX()) < tolerance && Math.abs(p1.getY() - p2.getY()) < tolerance;
    }
}

import java.util.ArrayList;
import java.util.List;

public class ArrayUtils {

    /**
     * Restituisce un nuovo array di Stringhe senza elementi null. Metodo interno utilizzato per normalizzare le liste di esclusione (array e collezioni). Si noti che {@link Arrays#sort(Object[])} genererà un {@link NullPointerException} se un elemento dell'array è <code>null</code>.
     * @param array L'array da controllare
     * @return L'array fornito o un nuovo array senza null.
     */
    static String[] toNoNullStringArray(Object[] array) {
        if (array == null) {
            return new String[0];
        }

        List<String> nonNullList = new ArrayList<>();
        for (Object element : array) {
            if (element != null) {
                nonNullList.add(element.toString());
            }
        }

        return nonNullList.toArray(new String[0]);
    }

    public static void main(String[] args) {
        // Test case
        Object[] testArray = { "Hello", null, "World", null, "Java" };
        String[] result = toNoNullStringArray(testArray);

        for (String str : result) {
            System.out.println(str);
        }
    }
}

import java.nio.file.Path;
import java.nio.file.Paths;

public class PathUtil {
    /** 
     * Applica il percorso relativo fornito al percorso dato, assumendo la separazione standard delle cartelle Java (cioè i separatori "/").
     * @param path il percorso da cui partire (di solito un percorso di file completo)
     * @param relativePath il percorso relativo da applicare (rispetto al percorso di file completo sopra)
     * @return il percorso di file completo che risulta dall'applicazione del percorso relativo
     */
    public static String applyRelativePath(String path, String relativePath) {
        Path basePath = Paths.get(path);
        Path resolvedPath = basePath.resolveSibling(relativePath);
        return resolvedPath.toString();
    }

    public static void main(String[] args) {
        String path = "/home/user/documents/file.txt";
        String relativePath = "../images/picture.png";
        String result = applyRelativePath(path, relativePath);
        System.out.println(result); // Output: /home/user/images/picture.png
    }
}

import java.util.*;

public class BucketReloader {

    /**
     * Sposta tutti i vertici dal bucket con etichetta {@code minLabel} al bucket con etichetta 0. 
     * Pulisce il bucket con etichetta {@code minLabel}. Aggiorna le etichette di conseguenza.
     * @param bucketsByLabel i buckets in cui sono memorizzati i vertici
     * @param labels le etichette dei vertici 
     * @param minLabel il valore minimo del bucket non vuoto
     */
    private void reload(List<Set<Integer>> bucketsByLabel, List<Integer> labels, int minLabel) {
        Set<Integer> minBucket = bucketsByLabel.get(minLabel);
        Set<Integer> zeroBucket = bucketsByLabel.get(0);

        // Sposta tutti i vertici dal bucket minLabel al bucket 0
        for (Integer vertex : minBucket) {
            zeroBucket.add(vertex);
            labels.set(vertex, 0); // Aggiorna l'etichetta del vertice a 0
        }

        // Pulisce il bucket con etichetta minLabel
        minBucket.clear();
    }
}

import java.nio.ByteBuffer;
import java.nio.charset.StandardCharsets;

public class OctetDecoder {

    /** 
     * Decodifica gli ottetti in caratteri utilizzando la decodifica UTF-8 e aggiunge i caratteri ad uno oggetto StringBuffer.
     * @return l'indice del prossimo carattere non controllato nella stringa da decodificare
     */
    private static int decodeOctets(int i, ByteBuffer bb, StringBuilder sb) {
        while (i < bb.remaining()) {
            byte b = bb.get(i);
            if ((b & 0x80) == 0) { // 1-byte character
                sb.append((char) b);
                i++;
            } else if ((b & 0xE0) == 0xC0) { // 2-byte character
                if (i + 1 < bb.remaining()) {
                    sb.append(new String(new byte[]{b, bb.get(i + 1)}, StandardCharsets.UTF_8));
                    i += 2;
                } else {
                    break; // incomplete character
                }
            } else if ((b & 0xF0) == 0xE0) { // 3-byte character
                if (i + 2 < bb.remaining()) {
                    sb.append(new String(new byte[]{b, bb.get(i + 1), bb.get(i + 2)}, StandardCharsets.UTF_8));
                    i += 3;
                } else {
                    break; // incomplete character
                }
            } else if ((b & 0xF8) == 0xF0) { // 4-byte character
                if (i + 3 < bb.remaining()) {
                    sb.append(new String(new byte[]{b, bb.get(i + 1), bb.get(i + 2), bb.get(i + 3)}, StandardCharsets.UTF_8));
                    i += 4;
                } else {
                    break; // incomplete character
                }
            } else {
                // Invalid UTF-8 byte, skip it
                i++;
            }
        }
        return i;
    }
}

import java.util.ArrayList;
import java.util.List;

public class StackMapFrameVisitor {
    private Frame currentFrame;
    private List<Frame> frames;

    public StackMapFrameVisitor() {
        frames = new ArrayList<>();
    }

    private static class Frame {
        int offset;
        int numLocal;
        int numStack;
        int nextIndex;

        Frame(int offset, int numLocal, int numStack) {
            this.offset = offset;
            this.numLocal = numLocal;
            this.numStack = numStack;
            this.nextIndex = 0;
        }
    }

    int visitFrameStart(final int offset, final int numLocal, final int numStack) {
        currentFrame = new Frame(offset, numLocal, numStack);
        frames.add(currentFrame);
        return currentFrame.nextIndex;
    }
}

import java.io.ByteArrayInputStream;
import java.io.DataInputStream;
import java.io.IOException;

public class ClassFileReader {
    private byte[] classFileBuffer;
    private int[] cpInfoOffsets;

    final String readUtf(final int constantPoolEntryIndex, final char[] charBuffer) {
        int offset = cpInfoOffsets[constantPoolEntryIndex];
        int utfLength = readUnsignedShort(offset);
        offset += 2;

        int charLength = 0;
        int currentOffset = offset;
        int endOffset = offset + utfLength;

        while (currentOffset < endOffset) {
            int currentByte = classFileBuffer[currentOffset++] & 0xFF;
            if ((currentByte & 0x80) == 0) {
                charBuffer[charLength++] = (char) currentByte;
            } else if ((currentByte & 0xE0) == 0xC0) {
                charBuffer[charLength++] = (char) (((currentByte & 0x1F) << 6) 
                    + (classFileBuffer[currentOffset++] & 0x3F));
            } else {
                charBuffer[charLength++] = (char) (((currentByte & 0xF) << 12)
                    + ((classFileBuffer[currentOffset++] & 0x3F) << 6) 
                    + (classFileBuffer[currentOffset++] & 0x3F));
            }
        }

        return new String(charBuffer, 0, charLength);
    }

    private int readUnsignedShort(final int offset) {
        byte[] classFileBuffer = this.classFileBuffer;
        return ((classFileBuffer[offset] & 0xFF) << 8) 
            | (classFileBuffer[offset + 1] & 0xFF);
    }
}

