import java.util.HashMap;
import java.util.Map;

public class Accumulator {
    private Map<String, Integer> accumulatorMap;

    public Accumulator() {
        accumulatorMap = new HashMap<>();
    }

    /**
     * Accumulate the value with existing value in the same given key.
     * @param key The key to accumulate value for
     * @param value The value to accumulate
     * @return The updated accumulated value
     */
    public int accumulate(String key, int value) {
        int currentValue = accumulatorMap.getOrDefault(key, 0);
        int newValue = currentValue + value;
        accumulatorMap.put(key, newValue);
        return newValue;
    }
}

import java.util.HashMap;
import java.util.Map;

public class MessageLogger {
    private Map<String, Integer> messageTimestamps;

    public MessageLogger() {
        messageTimestamps = new HashMap<>();
    }

    /**
     * यदि संदेश को दिए गए टाइमस्टैम्प में प्रिंट किया जाना चाहिए, तो true लौटाता है, अन्यथा false लौटाता है।
     * यदि यह विधि false लौटाती है, तो संदेश प्रिंट नहीं किया जाएगा। टाइमस्टैम्प सेकंड की ग्रैन्युलैरिटी में है।
     */
    public boolean shouldPrintMessage(int timestamp, String message) {
        if (messageTimestamps.containsKey(message)) {
            int lastTimestamp = messageTimestamps.get(message);
            if (timestamp - lastTimestamp >= 10) {
                messageTimestamps.put(message, timestamp);
                return true;
            } else {
                return false;
            }
        } else {
            messageTimestamps.put(message, timestamp);
            return true;
        }
    }

    public static void main(String[] args) {
        MessageLogger logger = new MessageLogger();
        System.out.println(logger.shouldPrintMessage(1, "foo")); // true
        System.out.println(logger.shouldPrintMessage(2, "bar")); // true
        System.out.println(logger.shouldPrintMessage(3, "foo")); // false
        System.out.println(logger.shouldPrintMessage(11, "foo")); // true
    }
}

import java.util.*;

public class BucketLabeler {

    public void moveVerticesFromMinLabelBucketToZero(
        Map<Integer, Set<Integer>> bucketsByLabel,
        Map<Integer, Integer> labels,
        int minLabel
    ) {
        // Get the bucket with minLabel
        Set<Integer> minLabelBucket = bucketsByLabel.get(minLabel);

        if (minLabelBucket == null || minLabelBucket.isEmpty()) {
            return;
        }

        // Get or create bucket 0
        Set<Integer> zeroBucket = bucketsByLabel.computeIfAbsent(0, k -> new HashSet<>());

        // Move all vertices from minLabel bucket to zero bucket
        for (Integer vertex : minLabelBucket) {
            // Update the label for each vertex to 0
            labels.put(vertex, 0);
            // Add vertex to zero bucket
            zeroBucket.add(vertex);
        }

        // Clear the minLabel bucket
        minLabelBucket.clear();

        // Remove empty bucket if it exists
        bucketsByLabel.remove(minLabel);
    }
}

