class ProfileAnalyzeTimeRange {
    private long startTime;
    private long endTime;

    public ProfileAnalyzeTimeRange(long startTime, long endTime) {
        this.startTime = startTime;
        this.endTime = endTime;
    }

    public long getStartTime() {
        return startTime;
    }

    public long getEndTime() {
        return endTime;
    }
}

class ThreadSnapshot {
    private long timestamp;
    private String threadInfo;

    public ThreadSnapshot(long timestamp, String threadInfo) {
        this.timestamp = timestamp;
        this.threadInfo = threadInfo;
    }

    public long getTimestamp() {
        return timestamp;
    }

    public String getThreadInfo() {
        return threadInfo;
    }
}

public class ThreadSnapshotLoader {

    /** 
     * निर्दिष्ट समय सीमा में थ्रेड स्नैपशॉट लोड करें
     */
    public static List<ThreadSnapshot> parseFromFileWithTimeRange(File file, List<ProfileAnalyzeTimeRange> timeRanges) throws IOException {
        List<ThreadSnapshot> snapshots = new ArrayList<>();

        try (BufferedReader br = new BufferedReader(new FileReader(file))) {
            String line;
            while ((line = br.readLine()) != null) {
                String[] parts = line.split(",");
                long timestamp = Long.parseLong(parts[0]);
                String threadInfo = parts[1];

                for (ProfileAnalyzeTimeRange range : timeRanges) {
                    if (timestamp >= range.getStartTime() && timestamp <= range.getEndTime()) {
                        snapshots.add(new ThreadSnapshot(timestamp, threadInfo));
                        break; // No need to check other ranges if already added
                    }
                }
            }
        }

        return snapshots;
    }
}

import java.util.HashMap;
import java.util.Map;

public class ConstantPool {
    private final Map<String, Integer> nameAndTypeMap = new HashMap<>();
    private int nextIndex = 1;

    /**
     * इस प्रतीक तालिका के स्थायी पूल में एक CONSTANT_NameAndType_info जोड़ता है। यदि स्थायी पूल में पहले से ही समान आइटम मौजूद है, तो कुछ नहीं करता है।
     * @param name एक फ़ील्ड या विधि का नाम।
     * @param descriptor एक फ़ील्ड या विधि का विवरण।
     * @return दिए गए मान के साथ एक नया या पहले से मौजूद प्रतीक।
     */
    public int addConstantNameAndType(final String name, final String descriptor) {
        String key = name + ":" + descriptor;
        if (nameAndTypeMap.containsKey(key)) {
            return nameAndTypeMap.get(key);
        } else {
            int index = nextIndex++;
            nameAndTypeMap.put(key, index);
            return index;
        }
    }
}

import java.util.List;
import java.util.Set;

public class BucketRelabeler {

    /**
     * {@code minLabel} लेबल वाले बकेट से सभी वर्टिस को लेबल 0 वाले बकेट में स्थानांतरित करता है। {@code minLabel} लेबल वाले बकेट को साफ करता है। लेबलिंग को तदनुसार अपडेट करता है।
     * @param bucketsByLabel वे बकेट जहाँ वर्टिस संग्रहीत हैं
     * @param labels वर्टिस के लेबल
     * @param minLabel गैर-खाली बकेट का न्यूनतम मान
     */
    private void reload(List<Set<Integer>> bucketsByLabel, List<Integer> labels, int minLabel) {
        if (minLabel < 0 || minLabel >= bucketsByLabel.size()) {
            throw new IllegalArgumentException("minLabel is out of bounds");
        }

        Set<Integer> minLabelBucket = bucketsByLabel.get(minLabel);
        Set<Integer> zeroLabelBucket = bucketsByLabel.get(0);

        // Move vertices from minLabel bucket to zero label bucket
        for (Integer vertex : minLabelBucket) {
            zeroLabelBucket.add(vertex);
            labels.set(vertex, 0); // Update the label of the vertex to 0
        }

        // Clear the minLabel bucket
        minLabelBucket.clear();
    }
}

