import java.util.Arrays;
import java.util.List;

public class ArrayToListConverter {
    /** 
     * एरे को लिस्ट में बदलें। <p> {@link Arrays#asList(Object)} की तरह काम करता है, लेकिन नल एरे को संभालता है।
     * @return एक लिस्ट जो एरे द्वारा समर्थित है।
     */
    public static <T> List<T> asList(T[] a) {
        if (a == null) {
            return Arrays.asList(); // Return an empty list for null array
        }
        return Arrays.asList(a);
    }

    public static void main(String[] args) {
        String[] array = {"Hello", "World"};
        List<String> list = asList(array);
        System.out.println(list); // Output: [Hello, World]

        String[] nullArray = null;
        List<String> emptyList = asList(nullArray);
        System.out.println(emptyList); // Output: []
    }
}

import java.util.List;
import java.util.ArrayList;
import java.util.Collections;

public class UpperBoundCalculator<K extends Comparable<K>> {

    /**
     * प्रत्येक कुंजी के लिए एक न्यूनतम ऊपरी सीमा खोजता है।
     * @param keys कुंजियों की एक सूची।
     * @return गणना की गई कुंजी की ऊपरी सीमा।
     */
    private List<Integer> computeUpperBounds(List<K> keys) {
        if (keys == null || keys.isEmpty()) {
            return Collections.emptyList();
        }

        List<Integer> upperBounds = new ArrayList<>();
        for (int i = 0; i < keys.size(); i++) {
            K currentKey = keys.get(i);
            int upperBound = Integer.MAX_VALUE;

            for (int j = i + 1; j < keys.size(); j++) {
                if (currentKey.compareTo(keys.get(j)) < 0) {
                    upperBound = j;
                    break;
                }
            }

            upperBounds.add(upperBound);
        }

        return upperBounds;
    }
}

import java.util.Collection;

public class CollectionUtils {
    /** 
     * जांचें कि दी गई संग्रह में दी गई तत्व उदाहरण मौजूद है या नहीं। <p>सुनिश्चित करता है कि दी गई उदाहरण मौजूद है, न कि समान तत्व के लिए <code>true</code> लौटाने के लिए।
     * @param collection जांचने के लिए संग्रह
     * @param element खोजने के लिए तत्व
     * @return <code>true</code> यदि पाया गया, <code>false</code> अन्यथा
     */
    public static boolean containsInstance(Collection<?> collection, Object element) {
        for (Object obj : collection) {
            if (obj == element) {
                return true;
            }
        }
        return false;
    }
}

