import java.util.Arrays;

public class ByteVector {
    private byte[] buffer;
    private int size;
    private static final int DEFAULT_CAPACITY = 64;

    public ByteVector() {
        buffer = new byte[DEFAULT_CAPACITY];
        size = 0;
    }

    public void enlarge(final int size) {
        if (size <= 0) {
            return;
        }

        int newCapacity = buffer.length;
        int minCapacity = size + this.size;

        // If current capacity is not enough
        if (minCapacity > newCapacity) {
            // Double the capacity until it's large enough
            while (newCapacity < minCapacity) {
                newCapacity = newCapacity * 2;
            }

            // Create new array and copy contents
            buffer = Arrays.copyOf(buffer, newCapacity);
        }
    }
}

public class StringMatcher {
    /**
     * Returns {@code true} if the given string matches the given substring at the given index, {@code false} otherwise.
     * @param str the original string (or StringBuilder) 
     * @param index the index in the original string to start matching against
     * @param substring the substring to match at the given index
     * @return {@code true} if the given string matches the given substring at the given index, {@code false} otherwise.
     */
    public static boolean matchesAt(CharSequence str, int index, String substring) {
        if (str == null || substring == null) {
            return false;
        }

        if (index < 0 || index + substring.length() > str.length()) {
            return false;
        }

        for (int i = 0; i < substring.length(); i++) {
            if (str.charAt(index + i) != substring.charAt(i)) {
                return false;
            }
        }

        return true;
    }
}

import java.util.Arrays;

public class ByteVector {
    private byte[] data;
    private int size;

    public ByteVector() {
        this.data = new byte[10]; // Initial capacity
        this.size = 0;
    }

    /** 
     * इस बाइट वेक्टर में बाइट्स का एक एरे डालता है। यदि आवश्यक हो तो बाइट वेक्टर को स्वचालित रूप से बढ़ा दिया जाता है।
     * @param byteArrayValue बाइट्स का एक एरे। {@code byteLength} नल बाइट्स डालने के लिए {@literal null} हो सकता है।
     * @param byteOffset byteArrayValue का पहला बाइट का अनुक्रमांक जो कॉपी किया जाना चाहिए।
     * @param byteLength byteArrayValue के बाइट्स की संख्या जो कॉपी की जानी चाहिए।
     * @return यह बाइट वेक्टर।
     */
    public ByteVector putByteArray(final byte[] byteArrayValue, final int byteOffset, final int byteLength) {
        if (byteArrayValue == null || byteLength <= 0) {
            return this;
        }

        ensureCapacity(size + byteLength);

        System.arraycopy(byteArrayValue, byteOffset, data, size, byteLength);
        size += byteLength;

        return this;
    }

    private void ensureCapacity(int minCapacity) {
        if (minCapacity - data.length > 0) {
            int newCapacity = Math.max(data.length * 2, minCapacity);
            data = Arrays.copyOf(data, newCapacity);
        }
    }

    public int size() {
        return size;
    }

    public byte[] toByteArray() {
        return Arrays.copyOf(data, size);
    }
}

import java.lang.Character;

/**
 * <p>इनपुट ऑब्जेक्ट को java.lang.Character में परिवर्तित करें।</p>
 * @param type वह डेटा प्रकार जिसमें इस मान को परिवर्तित किया जाना चाहिए।
 * @param value वह इनपुट मान जिसे परिवर्तित किया जाना है।
 * @return परिवर्तित मान।
 * @throws Exception यदि परिवर्तित करना सफलतापूर्वक नहीं किया जा सकता है
 * @since 1.8.0
 */
@Override
protected Object convertToType(final Class<?> type, final Object value) throws Exception {
    if (type != Character.class && type != char.class) {
        throw new Exception("Target type must be Character or char.");
    }

    if (value == null) {
        return null;
    }

    if (value instanceof Character) {
        return value;
    }

    if (value instanceof String) {
        String strValue = (String) value;
        if (strValue.length() == 1) {
            return strValue.charAt(0);
        } else {
            throw new Exception("String value must be exactly one character long.");
        }
    }

    if (value instanceof Number) {
        int intValue = ((Number) value).intValue();
        if (intValue >= Character.MIN_VALUE && intValue <= Character.MAX_VALUE) {
            return (char) intValue;
        } else {
            throw new Exception("Numeric value is out of range for a char.");
        }
    }

    throw new Exception("Cannot convert value to Character: " + value);
}

