public class MappingDiff {

    /**
     * उन मैपिंग्स को लौटाता है जिनमें ऐसे फ़ील्ड हैं जो इनपुट मैपिंग्स में मौजूद नहीं हैं। इनपुट मैपिंग्स को वर्तमान इंडेक्स से इतिहास मैपिंग होना चाहिए। वर्तमान इंडेक्स अपडेट संघर्ष से बचने के लिए _source कॉन्फ़िगरेशन को न लौटाएँ।
     */
    public Mappings diffStructure(String tableName, Mappings mappings) {
        Mappings result = new Mappings();
        Map<String, Object> currentFields = getCurrentMappings(tableName).getFields();
        Map<String, Object> inputFields = mappings.getFields();

        for (Map.Entry<String, Object> entry : currentFields.entrySet()) {
            String key = entry.getKey();
            if (!inputFields.containsKey(key)) {
                result.getFields().put(key, entry.getValue());
            }
        }

        return result;
    }

    // Dummy method to simulate fetching current mappings for a table
    private Mappings getCurrentMappings(String tableName) {
        Mappings currentMappings = new Mappings();
        Map<String, Object> fields = new HashMap<>();
        fields.put("field1", "type1");
        fields.put("field2", "type2");
        fields.put("field3", "type3");
        currentMappings.setFields(fields);
        return currentMappings;
    }

    public static void main(String[] args) {
        MappingDiff diff = new MappingDiff();
        Mappings inputMappings = new Mappings();
        Map<String, Object> inputFields = new HashMap<>();
        inputFields.put("field1", "type1");
        inputMappings.setFields(inputFields);

        Mappings result = diff.diffStructure("exampleTable", inputMappings);
        System.out.println(result.getFields()); // Output: {field2=type2, field3=type3}
    }
}

import java.util.HashSet;
import java.util.Set;

public class StringUtils {

    public static String deleteAny(String inString, String charsToDelete) {
        if (inString == null || charsToDelete == null) {
            return inString;
        }

        // Convert charsToDelete to Set for O(1) lookup
        Set<Character> deleteSet = new HashSet<>();
        for (char c : charsToDelete.toCharArray()) {
            deleteSet.add(c);
        }

        StringBuilder result = new StringBuilder();
        for (char c : inString.toCharArray()) {
            if (!deleteSet.contains(c)) {
                result.append(c);
            }
        }

        return result.toString();
    }
}

import java.nio.ByteBuffer;
import java.nio.charset.StandardCharsets;

public class ClassFileReader {
    private final byte[] classFileBuffer;

    public ClassFileReader(byte[] classFileBuffer) {
        this.classFileBuffer = classFileBuffer;
    }

    /**
     * {@link #classFileBuffer} में एक CONSTANT_Utf8 स्थायी पूल प्रविष्टि को पढ़ता है।
     * @param constantPoolEntryIndex कक्षा के स्थायी पूल तालिका में एक CONSTANT_Utf8 प्रविष्टि का अनुक्रमांक।
     * @param charBuffer वह बफर है जिसका उपयोग स्ट्रिंग पढ़ने के लिए किया जाएगा। यह बफर पर्याप्त बड़ा होना चाहिए। इसे स्वचालित रूप से आकार नहीं दिया जाता है।
     * @return निर्दिष्ट CONSTANT_Utf8 प्रविष्टि के लिए संबंधित String।
     */
    final String readUtf(final int constantPoolEntryIndex, final char[] charBuffer) {
        // Assuming the constant pool entry index points to the start of the CONSTANT_Utf8_info structure
        int offset = constantPoolEntryIndex;

        // Read the length of the UTF-8 string (2 bytes)
        int length = ((classFileBuffer[offset] & 0xFF) << 8) | (classFileBuffer[offset + 1] & 0xFF);
        offset += 2;

        // Decode the UTF-8 bytes into the char buffer
        ByteBuffer byteBuffer = ByteBuffer.wrap(classFileBuffer, offset, length);
        int charCount = StandardCharsets.UTF_8.decode(byteBuffer, charBuffer, 0, charBuffer.length).position();

        // Convert the char buffer to a String
        return new String(charBuffer, 0, charCount);
    }
}

import java.util.*;

public class GraphPathTransformer {

    public List<Integer> setToPath(Set<Edge> tour, Graph graph) {
        if (tour == null || tour.isEmpty() || graph == null) {
            return new ArrayList<>();
        }

        List<Integer> path = new ArrayList<>();
        Edge currentEdge = tour.iterator().next();
        int currentVertex = currentEdge.getSource();
        path.add(currentVertex);

        Set<Edge> remainingEdges = new HashSet<>(tour);
        remainingEdges.remove(currentEdge);

        while (!remainingEdges.isEmpty()) {
            currentVertex = currentEdge.getDestination();
            path.add(currentVertex);

            // Find next edge that connects to current vertex
            Edge nextEdge = null;
            for (Edge edge : remainingEdges) {
                if (edge.getSource() == currentVertex) {
                    nextEdge = edge;
                    break;
                } else if (edge.getDestination() == currentVertex) {
                    // Reverse edge direction if needed
                    nextEdge = new Edge(edge.getDestination(), edge.getSource(), edge.getWeight());
                    break;
                }
            }

            if (nextEdge == null) {
                break; // No connecting edge found
            }

            currentEdge = nextEdge;
            remainingEdges.remove(nextEdge);
        }

        return path;
    }
}

