import java.util.Arrays;

public class ArrayMatcher {
    private int[] internalArray;

    public ArrayMatcher(int[] array) {
        this.internalArray = array;
    }

    /**
     * Returns true if the contents of the internal array and the provided array match.
     * @param otherArray The array to compare against the internal array
     * @return boolean indicating if arrays match
     */
    public boolean matches(int[] otherArray) {
        if (otherArray == null || internalArray == null) {
            return false;
        }

        if (otherArray.length != internalArray.length) {
            return false;
        }

        return Arrays.equals(internalArray, otherArray);
    }
}

def remove_ending_os_sep(input_list):
    import os

    # Handle None input
    if input_list is None:
        return []

    # Check input type
    if not isinstance(input_list, list):
        raise TypeError("Input must be a list")

    result = []

    # Process each string in list
    for path in input_list:
        # Skip if not string
        if not isinstance(path, str):
            result.append(path)
            continue

        # Skip if empty or single char
        if len(path) <= 1:
            result.append(path)
            continue

        # Remove trailing separator if exists
        if path[-1] == os.sep:
            result.append(path[:-1])
        else:
            result.append(path)

    return result

def scale(self, other=None):
    """
    获取或设置图表的比例。

    如果参数 *other* 为 ``None``，则返回此图表的比例。

    如果提供了一个数值类型的 *other*，则将图表重新缩放到该值。
    如果图表的比例未知或为零，对其重新缩放将会引发:exc: `~.LenaValueError` 异常。

    为了获得有意义的结果，将使用图表的字段。
    仅最后一个坐标会被重新缩放。
    例如，如果图表具有 *x* 和 *y* 坐标，则 *y* 会被重新缩放；对于三维图表，*z* 会被重新缩放。
    所有的误差值也会与其对应的坐标一起重新缩放。
    """
    if other is None:
        return self._scale
    elif isinstance(other, (int, float)):
        if self._scale == 0 or self._scale is None:
            raise LenaValueError("Cannot rescale chart with unknown or zero scale.")
        # Rescale the last coordinate
        if hasattr(self, 'z'):
            self.z *= other / self._scale
            if hasattr(self, 'z_error'):
                self.z_error *= other / self._scale
        elif hasattr(self, 'y'):
            self.y *= other / self._scale
            if hasattr(self, 'y_error'):
                self.y_error *= other / self._scale
        elif hasattr(self, 'x'):
            self.x *= other / self._scale
            if hasattr(self, 'x_error'):
                self.x_error *= other / self._scale
        self._scale = other
    else:
        raise TypeError("Scale must be a numeric value or None.")

from typing import List, Optional

def int_to_string(number: int, alphabet: List[str], padding: Optional[int] = None) -> str:
    """
    将一个数字使用给定的字母表转换为字符串。

    数字表示一个短的 UUID。

    输出的字符串以最高有效位（Most Significant Digit）优先。

    @param number: 整型值  
    @param alphabet: 包含字母的列表  
    @param padding: 可选参数，整型值，用于指定填充长度  
    @return: 与整型值对应的字符串值
    """
    base = len(alphabet)
    result = []

    while number > 0:
        remainder = number % base
        result.append(alphabet[remainder])
        number = number // base

    # Reverse to get the most significant digit first
    result.reverse()

    # Convert list to string
    result_str = ''.join(result)

    # Apply padding if specified
    if padding is not None:
        if len(result_str) < padding:
            result_str = alphabet[0] * (padding - len(result_str)) + result_str

    return result_str

def protocol_handlers(cls, protocol_version=None):
    """
    返回一个可用的 Bolt 协议处理程序的字典，以版本元组为键。如果提供了明确的协议版本，字典将包含零个或一个条目，具体取决于该版本是否受支持。如果未提供协议版本，将返回所有可用的版本。

    :param protocol_version: 标识特定协议版本的元组（例如 (3, 5)）或 None
    :return: 一个字典，键为版本元组，值为所有相关且受支持的协议版本的处理程序类
    :raise TypeError: 如果协议版本未以元组形式传入
    """
    # 假设我们有一些支持的协议版本及其对应的处理程序
    supported_handlers = {
        (3, 5): "BoltV3_5Handler",
        (4, 0): "BoltV4_0Handler",
        (4, 1): "BoltV4_1Handler",
    }

    if protocol_version is not None:
        if not isinstance(protocol_version, tuple):
            raise TypeError("协议版本必须以元组形式传入")
        if protocol_version in supported_handlers:
            return {protocol_version: supported_handlers[protocol_version]}
        else:
            return {}
    else:
        return supported_handlers

def generate_default_observer_schema(app):
    """
    为 ``spec.manifest`` 中的每个 Kubernetes 资源生成默认的观察者模式（observer schema），前提是尚未为其指定自定义的观察者模式。

    参数：
        app (krake.data.kubernetes.Application): 需要为其生成默认观察者模式的应用程序。
    """
    if not app.spec.observer:
        app.spec.observer = {}

    for resource in app.spec.manifest:
        # 获取资源的 kind 和 apiVersion
        kind = resource.get('kind')
        api_version = resource.get('apiVersion')

        # 如果资源没有 kind 或 apiVersion,跳过
        if not kind or not api_version:
            continue

        # 生成资源的唯一标识符
        resource_id = f"{api_version}/{kind}"

        # 如果该资源还没有观察者模式,则生成默认的
        if resource_id not in app.spec.observer:
            app.spec.observer[resource_id] = {
                "conditions": [
                    {
                        "type": "Available",
                        "status": "True"
                    }
                ]
            }

            # 为某些特定资源类型添加额外的默认观察条件
            if kind.lower() in ['deployment', 'statefulset', 'daemonset']:
                app.spec.observer[resource_id]["conditions"].append({
                    "type": "Progressing",
                    "status": "True"
                })

            # 为Job类型添加特定的完成条件
            if kind.lower() == 'job':
                app.spec.observer[resource_id]["conditions"] = [{
                    "type": "Complete",
                    "status": "True"
                }]

    return app

def plus_or_dot(pieces):
    """
    如果片段的闭合标签（closet-tag）中包含 "+"，则返回 "."；否则，返回 "+"。
    如果尚未存在“+”，则返回“+”，否则返回“.”。
    """
    if '+' in pieces:
        return '.'
    else:
        return '+'

def difference(d1, d2, level=-1):
    """
    返回一个字典，其中包含 *d1* 中不在 *d2* 中的项。

    参数 *level* 用于设置递归的最大深度。对于无限递归，则将其设置为-1。如果设置为 1，当某个键同时存在于 *d1* 和 *d2* 中但其值不同，则该键值对会包含在差异结果中。
    有关更多详细信息，请参阅 :func:`intersection`。

    *d1* 和 *d2* 本身不会被修改。然而，*d1* 或其某些子字典可能会直接作为返回值。如果需要，请对结果进行深拷贝。
    """
    result = {}

    # 遍历d1中的所有键值对
    for key, value in d1.items():
        # 如果键不在d2中，直接添加到结果中
        if key not in d2:
            result[key] = value
        # 如果键在d2中且level不为0
        elif level != 0:
            # 如果两个值都是字典，则递归比较
            if isinstance(value, dict) and isinstance(d2[key], dict):
                # 递归调用，level减1
                nested_diff = difference(value, d2[key], level - 1 if level > 0 else -1)
                if nested_diff:
                    result[key] = nested_diff
            # 如果值不相等，且level为1或-1，则添加到结果中
            elif value != d2[key]:
                result[key] = value

    return result

def get_nested_custom_and_control_args(self, args):
    """
    将输入参数分为控制，嵌套和自定义参数。

    控制参数：用于控制中间表示的行为。这些参数不会被写入到规范yml文件中。  
    嵌套参数：用于Ansible playbooks，并会被写入到规范yml文件中。  
    自定义参数：自定义的Ansible变量，用于替代常规的嵌套参数使用。

    :param args: 收集到的参数列表。
    :return: (dict, dict): 扁平化的字典（control_args, nested_args）
    """
    control_args = {}
    nested_args = {}

    for key, value in args.items():
        if key.startswith('control_'):
            control_args[key] = value
        elif key.startswith('nested_'):
            nested_args[key] = value
        else:
            nested_args[key] = value

    return control_args, nested_args

def validate(self, inventory, extract_spec_version=False):
    """
    验证给定的库存（inventory）。如果 `extract_spec_version` 为 True，则会根据 `type` 值来确定规范版本。如果没有 `type` 值或其无效，则其他测试将基于 `self.spec_version` 中给定的版本。
    验证给定的库存。

    如果 `extract_spec_version` 为真，则会根据 `type` 值来确定规范版本。
    如果没有 `type` 值或其无效，则其他测试将基于 `self.spec_version` 中给定的版本。
    """
    if extract_spec_version:
        if 'type' in inventory:
            spec_version = self.determine_spec_version(inventory['type'])
            if spec_version is None:
                spec_version = self.spec_version
        else:
            spec_version = self.spec_version
    else:
        spec_version = self.spec_version

    # Perform validation based on the determined spec_version
    if spec_version == "1.0":
        return self.validate_v1(inventory)
    elif spec_version == "2.0":
        return self.validate_v2(inventory)
    else:
        raise ValueError(f"Unsupported spec version: {spec_version}")

def determine_spec_version(self, type_value):
