from datetime import timedelta

def parse_frequency(frequency):
    if frequency is None or frequency.lower() == "always":
        return None

    try:
        parts = frequency.strip().split()
        if len(parts) != 2:
            raise ValueError("Invalid frequency format. Expected format: 'number timeunit'")

        num = int(parts[0])
        unit = parts[1].lower()

        if unit in ['days', 'day']:
            return timedelta(days=num)
        elif unit in ['weeks', 'week']:
            return timedelta(weeks=num)
        elif unit in ['hours', 'hour']:
            return timedelta(hours=num)
        elif unit in ['minutes', 'minute']:
            return timedelta(minutes=num)
        elif unit in ['seconds', 'second']:
            return timedelta(seconds=num)
        else:
            raise ValueError(f"Unsupported time unit: {unit}")

    except ValueError as e:
        raise ValueError(f"Failed to parse frequency: {frequency}. Error: {e}")

def get(self, key, default=None):
    """
    如果类中存在指定的键（key），则返回与该键对应的值；否则，返回默认值
    如果键 `k` 存在于字典 `D` 中,则`D.get(k[, d]) -> D[k]`；否则返回默认值 `None`。
    """
    return self.data.get(key, default)

def parser_flags(parser):
    flags = []
    for action in parser._actions:
        # Skip help action
        if action.dest == 'help':
            continue
        # Get all option strings (flags) for this action
        flags.extend(action.option_strings)
    # Sort flags and join with spaces
    return ' '.join(sorted(flags))

def protocol_handlers(cls, protocol_version=None):
    """
    根据 `protocol_version` 的值，返回不同形式的 Bolt 协议处理程序。
    返回一个包含可用 Bolt 协议处理程序的字典，字典的键是版本元组。如果提供了明确的协议版本，该字典将包含零个或一个条目，具体取决于该版本是否受支持。如果未提供协议版本，将返回所有可用的版本。

    :param protocol_version: 标识特定协议版本的元组（例如 (3, 5)）或 None
    :return: 一个字典，键为版本元组，值为对应的处理程序类，包含所有相关且受支持的协议版本
    :raise TypeError: 当传入的协议版本不是元组类型时
    """
    # 假设这是所有支持的协议版本及其对应的处理程序
    supported_versions = {
        (3, 5): "BoltProtocolHandlerV3_5",
        (4, 0): "BoltProtocolHandlerV4_0",
        (4, 1): "BoltProtocolHandlerV4_1",
        (4, 2): "BoltProtocolHandlerV4_2",
    }

    if protocol_version is not None:
        if not isinstance(protocol_version, tuple):
            raise TypeError("protocol_version must be a tuple or None")
        if protocol_version in supported_versions:
            return {protocol_version: supported_versions[protocol_version]}
        else:
            return {}
    else:
        return supported_versions

def validate_version_inventories(self, version_dirs):
    """
    每个版本**应当**包含截至该版本的完整清单。  

    同时，记录所有与根清单不同的内容摘要，以便在验证内容时能够检查这些差异。  

    `version_dirs` 是一个包含版本目录名称的数组，并假定按照版本顺序排列（1, 2, 3...）。
    """
    # 存储每个版本的清单差异
    version_diffs = {}

    # 获取根目录清单
    root_inventory = self.get_root_inventory()

    # 遍历每个版本目录
    for version in version_dirs:
        version_inventory = self.get_version_inventory(version)

        # 检查是否包含完整清单
        if not version_inventory:
            raise ValueError(f"Version {version} missing complete inventory")

        # 与根清单比较,记录差异
        diffs = {}
        for file_path, checksum in version_inventory.items():
            if file_path not in root_inventory:
                diffs[file_path] = {'status': 'added', 'checksum': checksum}
            elif root_inventory[file_path] != checksum:
                diffs[file_path] = {
                    'status': 'modified',
                    'old_checksum': root_inventory[file_path],
                    'new_checksum': checksum
                }

        for file_path in root_inventory:
            if file_path not in version_inventory:
                diffs[file_path] = {
                    'status': 'deleted',
                    'old_checksum': root_inventory[file_path]
                }

        # 存储该版本的差异
        if diffs:
            version_diffs[version] = diffs

    return version_diffs

def plugins_manager(cls):
    """
    通过 `cls._get_service()` 中的 `ServiceName.PLUGINS_MANAGER` 获取插件管理器。
    获取插件管理器。
    """
    return cls._get_service(ServiceName.PLUGINS_MANAGER)

def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    给定一个参数序列和一个从子解析器名称到 argparse.ArgumentParser 实例的字典，让每个请求的操作的子解析器尝试解析所有参数。这允许共享常见参数（例如 --repository）给多个子解析器。

    将结果作为一个元组返回，其中包含一个将子解析器名称映射到其解析后的 argparse.Namespace 实例的字典和一个包含未被任何子解析器认领的剩余参数的列表。
    """
    parsed_results = {}
    remaining_args = list(unparsed_arguments)

    for subparser_name, parser in subparsers.items():
        try:
            parsed_args, remaining = parser.parse_known_args(unparsed_arguments)
            parsed_results[subparser_name] = parsed_args
            remaining_args = remaining
        except SystemExit:
            # Ignore SystemExit exceptions raised by argparse when parsing fails
            continue

    return parsed_results, remaining_args

import java.util.Map;

public class CustomMap<K,V> implements Map<K,V> {

    private Entry<K,V>[] table;

    /**
     * 如果此映射包含指定键的映射，则返回<code>true</code>。
     * @param key 要搜索的键
     * @return 如果映射包含该键，则返回真
     */
    @Override
    public boolean containsKey(final Object key) {
        if (key == null) {
            for (Entry<K,V> entry : table) {
                if (entry != null && entry.getKey() == null) {
                    return true;
                }
            }
        } else {
            for (Entry<K,V> entry : table) {
                if (entry != null && key.equals(entry.getKey())) {
                    return true;
                }
            }
        }
        return false;
    }
}

import java.io.DataOutput;
import java.io.IOException;

public class LinkedBufferWriter {

    /**
     * 将 {@link LinkedBuffer} 的内容写入 {@link DataOutput}。
     * @return 缓冲区的总内容大小。
     */
    public static int writeTo(final DataOutput out, LinkedBuffer node) throws IOException {
        if (out == null || node == null) {
            return 0;
        }

        int totalSize = 0;
        LinkedBuffer current = node;

        while (current != null) {
            byte[] buffer = current.getBuffer();
            int offset = current.getOffset();
            int size = current.getSize();

            if (buffer != null && size > 0) {
                out.write(buffer, offset, size);
                totalSize += size;
            }

            current = current.getNext();
        }

        return totalSize;
    }
}

// Helper class to represent a LinkedBuffer node
class LinkedBuffer {
    private byte[] buffer;
    private int offset;
    private int size;
    private LinkedBuffer next;

    public byte[] getBuffer() {
        return buffer;
    }

    public int getOffset() {
        return offset;
    }

    public int getSize() {
        return size;
    }

    public LinkedBuffer getNext() {
        return next;
    }
}

import java.util.Collection;

public class MatchFinder {
    /** 
     * 返回在 '<code>source</code>' 中包含的 '<code>candidates</code>' 的第一个元素。如果 '<code>candidates</code>' 中没有任何元素出现在 '<code>source</code>' 中，则返回 <code>null</code>。迭代顺序取决于 {@link Collection} 的具体实现。
     * @param source 源集合
     * @param candidates 要搜索的候选项
     * @return 第一个匹配的对象，如果未找到则返回 <code>null</code>
     */
    public static Object findFirstMatch(Collection source, Collection candidates) {
        for (Object candidate : candidates) {
            if (source.contains(candidate)) {
                return candidate;
            }
        }
        return null;
    }
}

import org.apache.log4j.AppenderSkeleton;
import org.apache.log4j.spi.LoggingEvent;
import java.io.IOException;
import java.io.PrintWriter;
import java.net.Socket;
import java.util.ArrayList;
import java.util.List;

public class SocketAppender extends AppenderSkeleton {

    private List<Socket> clients = new ArrayList<>();
    private List<PrintWriter> writers = new ArrayList<>();

    @Override
    protected void append(LoggingEvent event) {
        // 获取日志消息
        String message = layout.format(event);

        // 遍历所有连接的客户端
        for (int i = 0; i < writers.size(); i++) {
            try {
                PrintWriter writer = writers.get(i);
                // 检查连接是否还活着
                if (clients.get(i).isConnected()) {
                    writer.println(message);
                    writer.flush();
                } else {
                    // 移除断开的连接
                    writer.close();
                    clients.get(i).close();
                    writers.remove(i);
                    clients.remove(i);
                    i--;
                }
            } catch (IOException e) {
                // 发生错误时移除连接
                try {
                    writers.get(i).close();
                    clients.get(i).close();
                } catch (IOException ex) {
                    // 忽略关闭时的错误
                }
                writers.remove(i);
                clients.remove(i);
                i--;
            }
        }
    }

    // 添加新的客户端连接
    public void addClient(Socket client) throws IOException {
        clients.add(client);
        writers.add(new PrintWriter(client.getOutputStream(), true));
    }

    @Override
    public void close() {
        // 关闭所有连接
        for (int i = 0; i < clients.size(); i++) {
            try {
                writers.get(i).close();
                clients.get(i).close();
            } catch (IOException e) {
                // 忽略关闭时的错误
            }
        }
        clients.clear();
        writers.clear();
    }

    @Override
    public boolean requiresLayout() {
        return true;
    }
}

import java.lang.reflect.Type;
