import java.nio.ByteBuffer;

public class ClassReader {
    private byte[] classData;

    public ClassReader(byte[] classData) {
        this.classData = classData;
    }

    /**
     * 在此 {@link ClassReader} 中读取一个有符号的长整型值。<i>此方法旨在用于 {@link Attribute} 子类，通常不用于类生成器或适配器。</i>
     * @param offset 要读取的值在此 {@link ClassReader} 中的起始偏移量。
     * @return 读取的值。
     */
    public long readLong(final int offset) {
        if (offset < 0 || offset + 8 > classData.length) {
            throw new IndexOutOfBoundsException("Offset is out of bounds");
        }
        return ByteBuffer.wrap(classData, offset, 8).getLong();
    }
}

import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.List;

public class TelnetServer {
    private List<PrintWriter> clientWriters = new ArrayList<>();

    /**
     * 以适用于 Telnet 的格式向每个客户端发送消息。
     */
    public synchronized void send(final String message) {
        // 遍历所有客户端的输出流
        for (PrintWriter writer : clientWriters) {
            try {
                // 发送消息,添加回车换行符以适配Telnet协议
                writer.println(message);
                writer.flush();
            } catch (Exception e) {
                // 如果发送失败,从列表中移除该客户端
                clientWriters.remove(writer);
            }
        }
    }

    // 添加新的客户端连接
    public synchronized void addClient(PrintWriter writer) {
        clientWriters.add(writer);
    }

    // 移除客户端连接
    public synchronized void removeClient(PrintWriter writer) {
        clientWriters.remove(writer);
    }
}

