public class StringUtil {
    /**
     * 去除给定字符串的前导空白字符。
     * @param str 要检查的字符串
     * @return 去除空白后的字符串
     * @see java.lang.Character#isWhitespace
     */
    public static String trimLeadingWhitespace(String str) {
        if (str == null) {
            return null;
        }
        int index = 0;
        while (index < str.length() && Character.isWhitespace(str.charAt(index))) {
            index++;
        }
        return str.substring(index);
    }

    public static void main(String[] args) {
        String testString = "   Hello, World!";
        String trimmedString = trimLeadingWhitespace(testString);
        System.out.println("'" + trimmedString + "'"); // Output: 'Hello, World!'
    }
}

public class HexConverter {

    /** 
     * @param b 一个 ASCII 编码的字符，范围为 0-9、a-f、A-F
     * @return 字符的字节值，范围为 0-16。
     */
    public static byte convertHexDigit(byte b) {
        if (b >= '0' && b <= '9') {
            return (byte) (b - '0');
        } else if (b >= 'a' && b <= 'f') {
            return (byte) (b - 'a' + 10);
        } else if (b >= 'A' && b <= 'F') {
            return (byte) (b - 'A' + 10);
        } else {
            throw new IllegalArgumentException("Invalid hex digit: " + (char) b);
        }
    }

    public static void main(String[] args) {
        // Test cases
        System.out.println(convertHexDigit((byte) '0')); // 0
        System.out.println(convertHexDigit((byte) '9')); // 9
        System.out.println(convertHexDigit((byte) 'a')); // 10
        System.out.println(convertHexDigit((byte) 'f')); // 15
        System.out.println(convertHexDigit((byte) 'A')); // 10
        System.out.println(convertHexDigit((byte) 'F')); // 15
    }
}

import java.util.Arrays;

public class Parser {
    private String input;
    private int currentPosition;

    public Parser(String input) {
        this.input = input;
        this.currentPosition = 0;
    }

    /**
     * 解析一个令牌，直到遇到某个给定的终止符。
     * @param terminators 终止字符数组。遇到这些字符中的任何一个都表示令牌的结束
     * @return 令牌
     */
    private String parseToken(final char[] terminators) {
        StringBuilder token = new StringBuilder();

        while (currentPosition < input.length()) {
            char currentChar = input.charAt(currentPosition);

            // 检查是否遇到终止符
            if (Arrays.binarySearch(terminators, currentChar) >= 0) {
                break;
            }

            token.append(currentChar);
            currentPosition++;
        }

        return token.toString();
    }
}

import java.util.HashSet;
import java.util.Set;

public class SetOperations<V> {
    /** 
     * 高效计算两个集合交集的方法
     * @param set1 集合 $1$
     * @param set2 集合 $2$
     * @return 集合 $1$ 和 $2$ 的交集
     */
    private Set<V> intersection(Set<V> set1, Set<V> set2) {
        // Create a new set to store intersection
        Set<V> result = new HashSet<>();

        // Choose smaller set to iterate over for better performance
        Set<V> smallerSet = set1.size() < set2.size() ? set1 : set2;
        Set<V> largerSet = set1.size() < set2.size() ? set2 : set1;

        // Iterate through smaller set and check if elements exist in larger set
        for (V element : smallerSet) {
            if (largerSet.contains(element)) {
                result.add(element);
            }
        }

        return result;
    }
}

import java.io.File;
import java.nio.file.Path;
import java.nio.file.Paths;

public class PathUtils {
    /**
     * 将给定的相对路径应用于给定路径，假设使用标准的Java文件夹分隔符（即"/"分隔符）。
     * @param path 起始路径（通常是完整的文件路径）
     * @param relativePath 要应用的相对路径（相对于上述完整文件路径）
     * @return 应用相对路径后得到的完整文件路径
     */
    public static String applyRelativePath(String path, String relativePath) {
        if (path == null || relativePath == null) {
            return null;
        }

        // 标准化路径分隔符
        path = path.replace('\\', '/');
        relativePath = relativePath.replace('\\', '/');

        // 如果relativePath是绝对路径，直接返回
        if (relativePath.startsWith("/")) {
            return relativePath;
        }

        // 使用Path API处理路径
        Path basePath = Paths.get(path);
        // 如果path是文件，获取其父目录
        if (!path.endsWith("/")) {
            basePath = basePath.getParent();
        }

        if (basePath == null) {
            return relativePath;
        }

        // 解析并规范化路径
        Path resolvedPath = basePath.resolve(relativePath).normalize();

        // 转换为字符串并确保使用正斜杠
        return resolvedPath.toString().replace('\\', '/');
    }
}

