import java.net.URI;
import java.net.URISyntaxException;
import java.util.ArrayList;
import java.util.List;

public class PathSegmentDecoder {

    /** 
     * 将URI的路径组件解码为路径段。
     * @param u URI。如果路径组件是绝对路径组件，则忽略前导'/'，并且不将其视为路径段的分隔符。
     * @param decode 如果路径组件的路径段应该以解码形式返回，则为真。
     * @return 路径段的列表。
     */
    public static List<PathSegmentImpl> decodePath(URI u, boolean decode) {
        List<PathSegmentImpl> segments = new ArrayList<>();
        String path = u.getPath();

        // 如果是绝对路径，忽略前导'/'
        if (path.startsWith("/")) {
            path = path.substring(1);
        }

        String[] pathParts = path.split("/");

        for (String part : pathParts) {
            if (decode) {
                part = decodeURIComponent(part);
            }
            segments.add(new PathSegmentImpl(part));
        }

        return segments;
    }

    private static String decodeURIComponent(String component) {
        try {
            return java.net.URLDecoder.decode(component, "UTF-8");
        } catch (Exception e) {
            return component; // 返回原始组件以防解码失败
        }
    }

    public static class PathSegmentImpl {
        private String segment;

        public PathSegmentImpl(String segment) {
            this.segment = segment;
        }

        public String getSegment() {
            return segment;
        }

        @Override
        public String toString() {
            return segment;
        }
    }
}

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class FileReverser {

    /**
     * 以逆序添加指定的文件。
     * @param files 输入流数组，表示要逆序添加的文件
     */
    private void addReverse(final InputStream[] files) {
        if (files == null) {
            throw new IllegalArgumentException("Files array cannot be null");
        }

        List<byte[]> fileContents = new ArrayList<>();

        // 读取所有文件内容到内存
        for (InputStream file : files) {
            if (file == null) {
                throw new IllegalArgumentException("File input stream cannot be null");
            }

            try (ByteArrayOutputStream buffer = new ByteArrayOutputStream()) {
                int nRead;
                byte[] data = new byte[1024];
                while ((nRead = file.read(data, 0, data.length)) != -1) {
                    buffer.write(data, 0, nRead);
                }
                buffer.flush();
                fileContents.add(buffer.toByteArray());
            } catch (IOException e) {
                throw new RuntimeException("Failed to read file content", e);
            }
        }

        // 逆序文件内容
        Collections.reverse(fileContents);

        // 处理逆序后的文件内容（例如写入到输出流或进行其他操作）
        for (byte[] content : fileContents) {
            // 这里可以根据需要处理逆序后的文件内容
            // 例如：System.out.write(content);
        }
    }
}

public class ByteArrayConverter {

    /** 
     * <p>将对象类型的 Byte 数组转换为基本数据类型的 byte 数组。</p> 
     * <p>对于 <code>null</code> 输入数组，此方法返回 <code>null</code>。</p>
     * @param array  一个 <code>Byte</code> 数组，可以是 <code>null</code>
     * @return 一个 <code>byte</code> 数组，如果输入数组为 null 则返回 <code>null</code>
     * @throws NullPointerException 如果数组内容为 <code>null</code>
     */
    public static byte[] toPrimitive(final Byte[] array) {
        if (array == null) {
            return null;
        }
        byte[] result = new byte[array.length];
        for (int i = 0; i < array.length; i++) {
            if (array[i] == null) {
                throw new NullPointerException("Array element at index " + i + " is null");
            }
            result[i] = array[i];
        }
        return result;
    }

    public static void main(String[] args) {
        // Example usage
        Byte[] byteArray = {1, 2, 3, null}; // This will throw NullPointerException
        byte[] primitiveArray = toPrimitive(byteArray);
    }
}

import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;
import java.util.ArrayList;
import java.util.List;

public class TypeResolver {

    /**
     * 使用 {@code targetType} 的类型变量信息解析 {@code genericType} 的参数。如果 {@code genericType} 不是参数化的，或者无法解析参数，则返回 {@code null}。
     */
    public static Class<?>[] resolveArguments(Type genericType, Class<?> targetType) {
        if (!(genericType instanceof ParameterizedType)) {
            return null;
        }

        ParameterizedType parameterizedType = (ParameterizedType) genericType;
        Type[] actualTypeArguments = parameterizedType.getActualTypeArguments();
        List<Class<?>> resolvedTypes = new ArrayList<>();

        for (Type typeArgument : actualTypeArguments) {
            if (typeArgument instanceof Class) {
                resolvedTypes.add((Class<?>) typeArgument);
            } else {
                // Handle other cases like TypeVariable, WildcardType, etc.
                // For simplicity, we return null if any type argument is not a Class.
                return null;
            }
        }

        return resolvedTypes.toArray(new Class<?>[0]);
    }

    public static void main(String[] args) {
        // Example usage
        Type genericType = new ParameterizedType() {
            @Override
            public Type[] getActualTypeArguments() {
                return new Type[] { String.class, Integer.class };
            }

            @Override
            public Type getRawType() {
                return List.class;
            }

            @Override
            public Type getOwnerType() {
                return null;
            }
        };

        Class<?>[] resolvedArgs = resolveArguments(genericType, List.class);
        if (resolvedArgs != null) {
            for (Class<?> clazz : resolvedArgs) {
                System.out.println(clazz.getSimpleName());
            }
        } else {
            System.out.println("Unable to resolve type arguments.");
        }
    }
}

/**
 * 将字符解释为数字（在任何基数下最多为36），并返回其数值。这类似于 {@code Character.digit()}，但我们不接受非ASCII数字。
 */
private static int digitValue(final char c) {
    if (c >= '0' && c <= '9') {
        return c - '0';
    } else if (c >= 'A' && c <= 'Z') {
        return 10 + (c - 'A');
    } else if (c >= 'a' && c <= 'z') {
        return 10 + (c - 'a');
    } else {
        return -1; // 非ASCII数字或无效字符
    }
}

import java.util.NoSuchElementException;

public class LinkedList<E> {
    private class ListNode<E> {
        private E data;
        private ListNode<E> next;
        private ListNode<E> prev;

        public ListNode(E data) {
            this.data = data;
            this.next = null;
            this.prev = null;
        }
    }

    private ListNode<E> current;

    /**
     * Returns the previous node in the linked list
     * @return The previous ListNode
     * @throws NoSuchElementException if there is no previous node
     */
    @Override
    public ListNode<E> previousNode() {
        if (current == null || current.prev == null) {
            throw new NoSuchElementException("No previous node exists");
        }
        current = current.prev;
        return current;
    }
}

import java.util.ArrayList;
import java.util.Enumeration;
import java.util.List;

public class EnumerationUtils {
    /**
     * 将给定的枚举值复制到字符串数组中。枚举值必须仅包含字符串元素。
     * @param enumeration 要复制的枚举值
     * @return 字符串数组（如果传入的枚举为 <code>null</code>，则返回 <code>null</code>）
     */
    public static String[] toStringArray(Enumeration<String> enumeration) {
        if (enumeration == null) {
            return null;
        }

        List<String> list = new ArrayList<>();
        while (enumeration.hasMoreElements()) {
            list.add(enumeration.nextElement());
        }

        return list.toArray(new String[0]);
    }
}

public class ArrayUtils {
    /**
     * 比较数组 <code>a</code> 和 <code>b</code> 中的前 <code>count</code> 个字节。
     * @param a     第一个要比较的数组。
     * @param b     第二个要比较的数组。
     * @param count 要比较的字节数。
     * @return 如果数组 <code>a</code> 和 <code>b</code> 中的前 <code>count</code> 个字节相等，则返回 <code>true</code>。
     */
    public static boolean arrayequals(byte[] a, byte[] b, int count) {
        if (a == b) {
            return true;
        }

        if (a == null || b == null) {
            return false;
        }

        if (count < 0) {
            return false;
        }

        if (a.length < count || b.length < count) {
            return false;
        }

        for (int i = 0; i < count; i++) {
            if (a[i] != b[i]) {
                return false;
            }
        }

        return true;
    }
}

import java.util.Set;

public class Graph<V> {

    /**
     * 计算进入一个顶点的权重总和
     * @param v 顶点
     * @return 进入一个顶点的权重总和
     */
    public double vertexWeight(Set<V> v) {
        double totalWeight = 0.0;
        // 假设我们有一个邻接表来表示图的结构
        // 这里假设邻接表中的每个顶点都有一个与之关联的权重
        // 遍历所有顶点，累加进入该顶点的权重
        for (V vertex : v) {
            // 假设 getIncomingEdges 返回进入该顶点的所有边的集合
            // 假设 getWeight 返回边的权重
            for (Edge<V> edge : getIncomingEdges(vertex)) {
                totalWeight += edge.getWeight();
            }
        }
        return totalWeight;
    }

    // 假设的辅助方法，返回进入某个顶点的所有边
    private Set<Edge<V>> getIncomingEdges(V vertex) {
        // 这里应该返回进入该顶点的所有边的集合
        // 由于这是一个示例，我们返回一个空的集合
        return Set.of();
    }

    // 假设的边类
    private static class Edge<V> {
        private final double weight;

        public Edge(double weight) {
            this.weight = weight;
        }

        public double getWeight() {
            return weight;
        }
    }
}

/**
 * 判断给定的时间戳是否已经过期。
 * 
 * @param timestamp        当前时间的时间戳
 * @param expiredThreshold 表示最后更新时间与从缓存中移除的时间点之间的持续时间。
 * @return 真值表示该指标应该从缓存中移除。
 */
public boolean isExpired(long timestamp, long expiredThreshold) {
    long currentTime = System.currentTimeMillis();
    return (currentTime - timestamp) >= expiredThreshold;
}

import com.alibaba.fastjson2.JSONWriter;
import com.alibaba.fastjson2.JSON;

public class JSONSerializer {

    private Object value;

    public JSONSerializer(Object value) {
        this.value = value;
    }

    /**
     * 序列化为 JSON {@link String}
     * @param features 在序列化中启用的特性
     * @return JSON {@link String}
     */
    @SuppressWarnings("unchecked")
    public String toString(JSONWriter.Feature... features) {
        if (value == null) {
            return null;
        }

        if (features == null || features.length == 0) {
            return JSON.toJSONString(value);
        }

        return JSON.toJSONString(value, features);
    }
}

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;

public class ClassFileBuffer {
    private byte[] buffer;
    private int size;

    public ClassFileBuffer() {
        this.buffer = new byte[0];
        this.size = 0;
    }

    /**
     * 清空并用提供的字节流填充此 {@code ClassFileBuffer} 的缓冲区。读取指针重置为字节数组的起始位置。
     */
    public void readFrom(final InputStream in) throws IOException {
        // Clear the existing buffer
        this.buffer = new byte[0];
        this.size = 0;

        // Use ByteArrayOutputStream to read from InputStream
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        byte[] tempBuffer = new byte[1024];
        int bytesRead;

        // Read from the InputStream and write to ByteArrayOutputStream
        while ((bytesRead = in.read(tempBuffer)) != -1) {
            baos.write(tempBuffer, 0, bytesRead);
        }

        // Convert ByteArrayOutputStream to byte array
        this.buffer = baos.toByteArray();
        this.size = this.buffer.length;

        // Reset the read pointer (if applicable, depending on usage context)
        // In this case, we just ensure the buffer is filled with new data.
    }
}

public class ObjectToStringUtil {

    /**
     * 对象转字符串，当对象为空时返回空字符串，否则返回toString();
     */
    public static String toString(Object object) {
        return object == null ? "" : object.toString();
    }

    public static void main(String[] args) {
        // 测试用例
        Object obj1 = null;
        Object obj2 = "Hello, World!";
        Object obj3 = 12345;

        System.out.println(toString(obj1)); // 输出: ""
        System.out.println(toString(obj2)); // 输出: "Hello, World!"
        System.out.println(toString(obj3)); // 输出: "12345"
    }
}

import java.util.*;

class Logger {
    private Map<String, Integer> messageTimestamps;
    private static final int THROTTLE_WINDOW = 10; // 10 seconds window

    public Logger() {
        messageTimestamps = new HashMap<>();
    }

    public boolean shouldPrintMessage(int timestamp, String message) {
        // If message not seen before or last timestamp was more than 10 seconds ago
        if (!messageTimestamps.containsKey(message) || 
            timestamp - messageTimestamps.get(message) >= THROTTLE_WINDOW) {
            messageTimestamps.put(message, timestamp);
            return true;
        }
        return false;
    }
}

import java.util.Objects;

public class StringArrayUtils {
    /**
     * 修剪给定字符串数组的元素，对每个元素调用 <code>String.trim()</code> 方法。
     * @param array 原始字符串数组
     * @return 包含修剪后的元素的结果数组（大小相同）
     */
    public static String[] trimArrayElements(String[] array) {
        if (array == null) {
            return null;
        }

        String[] result = new String[array.length];
        for (int i = 0; i < array.length; i++) {
            result[i] = array[i] == null ? null : array[i].trim();
        }
        return result;
    }
}

import java.util.*;

public class GraphLabeling {
    /**
     * 将所有标签为 {@code minLabel} 的桶中的顶点移动到标签为 0 的桶中。清空标签为 {@code minLabel} 的桶。相应地更新标签。
     * @param bucketsByLabel 存储顶点的桶
     * @param labels 顶点的标签
     * @param minLabel 非空桶的最小值
     */
    private void reload(List<Set<Integer>> bucketsByLabel, List<Integer> labels, int minLabel) {
        // 获取标签为minLabel的桶中的所有顶点
        Set<Integer> minLabelBucket = bucketsByLabel.get(minLabel);

        // 将这些顶点移动到标签为0的桶中
        bucketsByLabel.get(0).addAll(minLabelBucket);

        // 更新这些顶点的标签为0
        for (Integer vertex : minLabelBucket) {
            labels.set(vertex, 0);
        }

        // 清空标签为minLabel的桶
        minLabelBucket.clear();
    }
}

import java.util.ArrayList;
import java.util.Collection;

public class CollectionToStringArray {

    /** 
     * 将给定的集合转换为字符串数组。返回的数组不包含 <code>null</code> 条目。请注意，{@link Arrays#sort(Object[])} 如果数组元素为 <code>null</code> 将抛出 {@link NullPointerException}。
     * @param collection 要转换的集合
     * @return 一个新的字符串数组。
     */
    static String[] toNoNullStringArray(Collection<?> collection) {
        if (collection == null) {
            return new String[0];
        }

        ArrayList<String> list = new ArrayList<>();
        for (Object obj : collection) {
            if (obj != null) {
                list.add(obj.toString());
            }
        }

        return list.toArray(new String[0]);
    }

    public static void main(String[] args) {
        // Example usage
        Collection<Object> collection = new ArrayList<>();
        collection.add("Hello");
        collection.add(null);
        collection.add("World");

        String[] result = toNoNullStringArray(collection);
        for (String str : result) {
            System.out.println(str);
        }
    }
}

import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class UriMatcher {

    private final String pattern;

    public UriMatcher(String pattern) {
        this.pattern = pattern;
    }

    /** 
     * 将URI与模式进行匹配。
     * @param uri 要与模板匹配的URI。
     * @return 匹配结果，如果没有匹配则返回空。
     */
    public final MatchResult match(CharSequence uri) {
        Pattern compiledPattern = Pattern.compile(pattern);
        Matcher matcher = compiledPattern.matcher(uri);

        if (matcher.matches()) {
            return new MatchResult(matcher);
        }
        return null; // No match found
    }

    public static class MatchResult {
        private final Matcher matcher;

        public MatchResult(Matcher matcher) {
            this.matcher = matcher;
        }

        public String group(int group) {
            return matcher.group(group);
        }

        public int groupCount() {
            return matcher.groupCount();
        }
    }

    public static void main(String[] args) {
        UriMatcher uriMatcher = new UriMatcher("^(http|https)://.*$");
        MatchResult result = uriMatcher.match("https://example.com");

        if (result != null) {
            System.out.println("Matched! Group count: " + result.groupCount());
        } else {
            System.out.println("No match found.");
        }
    }
}

